"""
Issuer Profile Views

API views for issuer profile and signatory management.
"""

from rest_framework import viewsets, status
from rest_framework.decorators import action
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated
from django.shortcuts import get_object_or_404

from organizations.models import Organization, Signatory, OrganizationMember
from organizations.serializers import (
    IssuerProfileSerializer,
    IssuerProfileUpdateSerializer,
    SignatorySerializer,
    SignatoryCreateSerializer,
    SignatoryUpdateSerializer,
)
from organizations.services.issuer_profile_service import IssuerProfileService
from organizations.services.signatory_service import SignatoryService


class IssuerProfileViewSet(viewsets.ViewSet):
    """
    ViewSet for issuer profile management.

    Endpoints:
    - GET /issuer/profile/ - Get current issuer profile
    - PATCH /issuer/profile/ - Update issuer profile
    """

    permission_classes = [IsAuthenticated]

    def get_issuer_organization(self, request):
        """Get the issuer organization for the current user."""
        membership = OrganizationMember.objects.filter(
            user=request.user,
            role_in_org__in=['issuer_staff', 'manager']
        ).first()

        if not membership:
            return None

        return membership.organization

    def list(self, request):
        """Get current issuer profile."""
        organization = self.get_issuer_organization(request)

        if not organization:
            return Response(
                {'error': 'User is not associated with any issuer organization'},
                status=status.HTTP_403_FORBIDDEN
            )

        profile_data = IssuerProfileService.get_issuer_profile(organization)
        return Response(profile_data, status=status.HTTP_200_OK)

    def partial_update(self, request):
        """Update issuer profile."""
        organization = self.get_issuer_organization(request)

        if not organization:
            return Response(
                {'error': 'User is not associated with any issuer organization'},
                status=status.HTTP_403_FORBIDDEN
            )

        serializer = IssuerProfileUpdateSerializer(data=request.data)
        if not serializer.is_valid():
            return Response(serializer.errors, status=status.HTTP_400_BAD_REQUEST)

        try:
            updated_org = IssuerProfileService.update_issuer_profile(
                organization,
                serializer.validated_data
            )
            profile_data = IssuerProfileService.get_issuer_profile(updated_org)
            return Response(profile_data, status=status.HTTP_200_OK)
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_400_BAD_REQUEST
            )


class SignatoryViewSet(viewsets.ViewSet):
    """
    ViewSet for signatory management.

    Endpoints:
    - POST /issuer/signatories/ - Add signatory
    - GET /issuer/signatories/ - List signatories
    - PATCH /issuer/signatories/{id}/ - Update signatory
    - DELETE /issuer/signatories/{id}/ - Delete signatory
    - POST /issuer/signatories/{id}/set-primary/ - Set as primary
    """

    permission_classes = [IsAuthenticated]

    def get_issuer_organization(self, request):
        """Get the issuer organization for the current user."""
        membership = OrganizationMember.objects.filter(
            user=request.user,
            role_in_org__in=['issuer_staff', 'manager']
        ).first()

        if not membership:
            return None

        return membership.organization

    def create(self, request):
        """Add a new signatory."""
        organization = self.get_issuer_organization(request)

        if not organization:
            return Response(
                {'error': 'User is not associated with any issuer organization'},
                status=status.HTTP_403_FORBIDDEN
            )

        serializer = SignatoryCreateSerializer(data=request.data)
        if not serializer.is_valid():
            return Response(serializer.errors, status=status.HTTP_400_BAD_REQUEST)

        try:
            signatory = SignatoryService.add_signatory(
                organization=organization,
                **serializer.validated_data
            )
            response_serializer = SignatorySerializer(signatory)
            return Response(response_serializer.data, status=status.HTTP_201_CREATED)
        except ValueError as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_400_BAD_REQUEST
            )
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def list(self, request):
        """List all signatories for the issuer."""
        organization = self.get_issuer_organization(request)

        if not organization:
            return Response(
                {'error': 'User is not associated with any issuer organization'},
                status=status.HTTP_403_FORBIDDEN
            )

        signatories = SignatoryService.get_signatories(organization)
        serializer = SignatorySerializer(signatories, many=True)
        return Response(serializer.data, status=status.HTTP_200_OK)

    def partial_update(self, request, pk=None):
        """Update a signatory."""
        organization = self.get_issuer_organization(request)

        if not organization:
            return Response(
                {'error': 'User is not associated with any issuer organization'},
                status=status.HTTP_403_FORBIDDEN
            )

        signatory = get_object_or_404(
            Signatory,
            id=pk,
            organization=organization
        )

        serializer = SignatoryUpdateSerializer(data=request.data)
        if not serializer.is_valid():
            return Response(serializer.errors, status=status.HTTP_400_BAD_REQUEST)

        try:
            updated_signatory = SignatoryService.update_signatory(
                str(signatory.id),
                serializer.validated_data
            )
            response_serializer = SignatorySerializer(updated_signatory)
            return Response(response_serializer.data, status=status.HTTP_200_OK)
        except ValueError as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_400_BAD_REQUEST
            )
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def destroy(self, request, pk=None):
        """Delete a signatory."""
        organization = self.get_issuer_organization(request)

        if not organization:
            return Response(
                {'error': 'User is not associated with any issuer organization'},
                status=status.HTTP_403_FORBIDDEN
            )

        signatory = get_object_or_404(
            Signatory,
            id=pk,
            organization=organization
        )

        try:
            SignatoryService.delete_signatory(str(signatory.id))
            return Response(status=status.HTTP_204_NO_CONTENT)
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    @action(detail=True, methods=['post'])
    def set_primary(self, request, pk=None):
        """Set a signatory as primary."""
        organization = self.get_issuer_organization(request)

        if not organization:
            return Response(
                {'error': 'User is not associated with any issuer organization'},
                status=status.HTTP_403_FORBIDDEN
            )

        signatory = get_object_or_404(
            Signatory,
            id=pk,
            organization=organization
        )

        try:
            updated_signatory = SignatoryService.set_primary_signatory(str(signatory.id))
            response_serializer = SignatorySerializer(updated_signatory)
            return Response(response_serializer.data, status=status.HTTP_200_OK)
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )
