"""
FederatedMemberService — calls an issuer organization's external member API
to verify that a person is an active member before issuing a credential.
"""
from __future__ import annotations
import logging
import requests
from audit.services import AuditService

logger = logging.getLogger(__name__)

TIMEOUT = 10  # seconds


class FederatedVerificationError(Exception):
    pass


class MemberVerificationResult:
    def __init__(self, is_valid: bool, member_name: str, extra_claims: dict):
        self.is_valid = is_valid
        self.member_name = member_name
        self.extra_claims = extra_claims


class FederatedMemberService:
    @staticmethod
    def verify_member(organization, member_identifier: str, actor=None) -> MemberVerificationResult:
        """
        Call the organization's member API and verify the member.
        Raises FederatedVerificationError on failure.
        """
        try:
            config = organization.api_config
        except Exception:
            raise FederatedVerificationError(
                "No member API has been configured for this organization. "
                "Please configure the member verification API before issuing credentials."
            )

        if not config.is_active:
            raise FederatedVerificationError(
                "The member verification API for this organization is disabled."
            )

        url = config.api_base_url.rstrip('/') + '/' + config.member_verify_endpoint.lstrip('/')
        headers = {config.api_key_header: config.api_key_value}
        payload = {config.request_id_field: member_identifier}

        try:
            response = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT)
        except requests.Timeout:
            _log_failure(organization, member_identifier, 'api_timeout', actor)
            raise FederatedVerificationError(
                f"The member verification API did not respond within {TIMEOUT} seconds (timeout). "
                "Please check the API is running and accessible."
            )
        except requests.ConnectionError as e:
            _log_failure(organization, member_identifier, 'api_unreachable', actor)
            raise FederatedVerificationError(
                f"Could not connect to the member verification API: {e}"
            )
        except Exception as e:
            _log_failure(organization, member_identifier, 'api_error', actor)
            raise FederatedVerificationError(f"Member API request failed: {e}")

        if response.status_code != 200:
            _log_failure(organization, member_identifier, 'api_non_200', actor)
            raise FederatedVerificationError(
                f"Member verification API returned HTTP {response.status_code}. "
                f"Response: {response.text[:300]}"
            )

        try:
            data = response.json()
        except Exception:
            _log_failure(organization, member_identifier, 'invalid_response', actor)
            raise FederatedVerificationError(
                "Member verification API returned a non-JSON response."
            )

        # Check membership status
        status_val = data.get(config.response_status_field)
        is_active = _truthy(status_val)

        if not is_active:
            _log_failure(organization, member_identifier, 'member_not_found', actor)
            raise FederatedVerificationError(
                f"The person with identifier '{member_identifier}' could not be verified as "
                f"an active member of {organization.name}. "
                f"The organization's system returned: {config.response_status_field}={status_val!r}"
            )

        member_name = str(data.get(config.response_name_field, '') or '')

        # Extract extra fields
        extra_claims: dict = {}
        if isinstance(config.response_extra_fields, dict):
            for resp_field, claim_name in config.response_extra_fields.items():
                if resp_field in data:
                    extra_claims[claim_name] = data[resp_field]

        logger.info(
            "FederatedMemberService: verified member %s for org %s",
            member_identifier, organization.name
        )
        if actor:
            try:
                AuditService.log(
                    user=actor,
                    action='federated_member_verified',
                    entity_type='Organization',
                    entity_id=organization.id,
                    metadata={'member_identifier': member_identifier, 'org': str(organization.id)},
                )
            except Exception:
                pass

        return MemberVerificationResult(
            is_valid=True,
            member_name=member_name,
            extra_claims=extra_claims,
        )


def _truthy(val) -> bool:
    if val is None:
        return False
    if isinstance(val, bool):
        return val
    if isinstance(val, str):
        return val.lower() in ('true', '1', 'yes', 'active', 'valid')
    if isinstance(val, (int, float)):
        return bool(val)
    return False


def _log_failure(organization, member_identifier: str, reason: str, actor=None):
    logger.warning(
        "FederatedMemberService: verification FAILED for member=%s org=%s reason=%s",
        member_identifier, organization.name, reason
    )
    if actor:
        try:
            AuditService.log(
                user=actor,
                action='federated_member_verification_failed',
                entity_type='Organization',
                entity_id=organization.id,
                metadata={
                    'member_identifier': member_identifier,
                    'reason': reason,
                    'org': str(organization.id),
                },
            )
        except Exception:
            pass

from .registration_views import (
    RegistrationStep1View, RegistrationStep1VerifyOTPView,
    RegistrationStep2View, RegistrationStep3View,
    RegistrationStep4View, RegistrationStep5View,
    RegistrationStatusView,
)
