"""
Issuer Organization Registration Wizard Views
POST /api/issuer/register/step-{1-5}/
GET  /api/issuer/register/status/{registration_id}/
"""
from __future__ import annotations
import random
import string
from datetime import timedelta
from django.utils import timezone
from django.contrib.auth.hashers import make_password
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework import status
from rest_framework.permissions import AllowAny
from rest_framework.parsers import MultiPartParser, FormParser, JSONParser

from organizations.models.issuer_registration import IssuerRegistration, RegistrationDocument
from common.email_service import EmailService


def _otp():
    return ''.join(random.choices(string.digits, k=6))


def _get_reg(registration_id):
    try:
        return IssuerRegistration.objects.get(id=registration_id)
    except IssuerRegistration.DoesNotExist:
        return None


class RegistrationStep1View(APIView):
    """POST /api/issuer/register/step-1/"""
    permission_classes = [AllowAny]

    def post(self, request):
        email = (request.data.get('email') or '').lower().strip()
        password = request.data.get('password', '')
        if not email or not password:
            return Response({'error': 'email and password are required'}, status=400)

        from django.contrib.auth import get_user_model
        User = get_user_model()
        if User.objects.filter(email=email).exists():
            return Response({'error': 'An account with this email already exists.'}, status=400)
        if IssuerRegistration.objects.filter(email=email, status__in=['submitted', 'under_review', 'approved']).exists():
            return Response({'error': 'A registration with this email is already pending or approved.'}, status=400)

        # Re-use existing draft or create new
        reg, created = IssuerRegistration.objects.update_or_create(
            email=email,
            defaults={
                'password_hash': make_password(password),
                'status': 'draft',
                'registration_step': 1,
                'email_verified': False,
            }
        )
        otp = _otp()
        reg.otp_code = otp
        reg.otp_expires_at = timezone.now() + timedelta(minutes=10)
        reg.save()

        EmailService.send(
            subject='Verify your email — CredWallet Issuer Registration',
            message=f'Your verification code is: {otp}\nThis code expires in 10 minutes.',
            recipient_list=[email],
        )

        return Response({
            'registration_id': str(reg.id),
            'message': 'Verification code sent to your email. Please check your inbox.',
        }, status=201)


class RegistrationStep1VerifyOTPView(APIView):
    """POST /api/issuer/register/step-1/verify-otp/"""
    permission_classes = [AllowAny]

    def post(self, request):
        registration_id = request.data.get('registration_id')
        otp = str(request.data.get('otp', '')).strip()

        reg = _get_reg(registration_id)
        if not reg:
            return Response({'error': 'Registration not found.'}, status=404)
        if reg.email_verified:
            return Response({'message': 'Email already verified.', 'registration_step': 2})
        if not otp or reg.otp_code != otp:
            return Response({'error': 'Invalid verification code.'}, status=400)
        if reg.otp_expires_at and timezone.now() > reg.otp_expires_at:
            return Response({'error': 'Verification code has expired. Please request a new one.'}, status=400)

        reg.email_verified = True
        reg.registration_step = 2
        reg.save()
        return Response({'message': 'Email verified successfully.', 'registration_step': 2})


class RegistrationStep2View(APIView):
    """POST /api/issuer/register/step-2/"""
    permission_classes = [AllowAny]

    def post(self, request):
        from organizations.models import OrganizationType
        registration_id = request.data.get('registration_id')
        reg = _get_reg(registration_id)
        if not reg:
            return Response({'error': 'Registration not found.'}, status=404)
        if not reg.email_verified:
            return Response({'error': 'Please verify your email first.'}, status=400)

        org_type_id = request.data.get('organization_type_id')
        org_type = None
        if org_type_id:
            try:
                org_type = OrganizationType.objects.get(id=org_type_id)
            except OrganizationType.DoesNotExist:
                return Response({'error': 'Invalid organization type.'}, status=400)

        reg.organization_name = request.data.get('organization_name', '').strip()
        reg.organization_type = org_type
        reg.address = request.data.get('address', '').strip()
        reg.phone = request.data.get('phone', '').strip()
        reg.website = request.data.get('website', '').strip()
        reg.contact_person_name = request.data.get('contact_person_name', '').strip()
        reg.contact_person_email = request.data.get('contact_person_email', '').strip()
        reg.registration_step = 3
        reg.save()

        return Response({'message': 'Organization details saved.', 'registration_step': 3})


class RegistrationStep3View(APIView):
    """POST /api/issuer/register/step-3/ (document upload)"""
    permission_classes = [AllowAny]
    parser_classes = [MultiPartParser, FormParser]

    def post(self, request):
        registration_id = request.data.get('registration_id')
        reg = _get_reg(registration_id)
        if not reg:
            return Response({'error': 'Registration not found.'}, status=404)

        files = request.FILES.getlist('files')
        doc_types = request.data.getlist('document_types')
        if not files:
            return Response({'error': 'At least one document must be uploaded.'}, status=400)

        uploaded = []
        for i, f in enumerate(files):
            doc_type = doc_types[i] if i < len(doc_types) else 'other'
            doc = RegistrationDocument.objects.create(
                registration=reg,
                document_type=doc_type,
                file=f,
                file_name=f.name,
            )
            uploaded.append({
                'id': str(doc.id),
                'document_type': doc.document_type,
                'file_name': doc.file_name,
            })

        reg.registration_step = 4
        reg.save()
        return Response({'message': 'Documents uploaded.', 'documents': uploaded, 'registration_step': 4})


class RegistrationStep4View(APIView):
    """POST /api/issuer/register/step-4/"""
    permission_classes = [AllowAny]

    def post(self, request):
        registration_id = request.data.get('registration_id')
        reg = _get_reg(registration_id)
        if not reg:
            return Response({'error': 'Registration not found.'}, status=404)

        reg.use_case_description = request.data.get('use_case_description', '').strip()
        intended = request.data.get('intended_credential_types', [])
        if isinstance(intended, str):
            import json
            try:
                intended = json.loads(intended)
            except Exception:
                intended = [intended]
        reg.intended_credential_types = intended
        reg.registration_step = 5
        reg.save()
        return Response({'message': 'Use case saved.', 'registration_step': 5})


class RegistrationStep5View(APIView):
    """POST /api/issuer/register/step-5/ — final submission"""
    permission_classes = [AllowAny]

    def post(self, request):
        registration_id = request.data.get('registration_id')
        reg = _get_reg(registration_id)
        if not reg:
            return Response({'error': 'Registration not found.'}, status=404)

        consent = request.data.get('consent', False)
        if not consent or consent in ('false', 'False', '0', 'no'):
            return Response({'error': 'You must agree to the platform terms to proceed.'}, status=400)

        reg.consent_agreed = True
        reg.consent_at = timezone.now()
        reg.status = 'submitted'
        reg.submitted_at = timezone.now()
        reg.registration_step = 6
        reg.save()

        # Notify admin
        try:
            from django.contrib.auth import get_user_model
            User = get_user_model()
            admins = User.objects.filter(role='admin', is_active=True)
            for admin in admins[:3]:
                if admin.email:
                    EmailService.send(
                        subject='New Issuer Registration Submitted',
                        message=f'A new issuer registration has been submitted by {reg.email} for {reg.organization_name}.',
                        recipient_list=[admin.email],
                    )
        except Exception:
            pass

        return Response({
            'message': 'Your application has been submitted successfully. '
                       'Our team will review it within 3-5 business days.',
            'registration_id': str(reg.id),
            'status': 'submitted',
        })


class RegistrationStatusView(APIView):
    """GET /api/issuer/register/status/{registration_id}/"""
    permission_classes = [AllowAny]

    def get(self, request, registration_id):
        reg = _get_reg(registration_id)
        if not reg:
            return Response({'error': 'Registration not found.'}, status=404)

        data = {
            'registration_id': str(reg.id),
            'status': reg.status,
            'current_step': reg.registration_step,
            'submitted_at': reg.submitted_at.isoformat() if reg.submitted_at else None,
            'organization_name': reg.organization_name,
            'email': reg.email,
        }
        if reg.status == 'rejected':
            data['rejection_reason'] = reg.rejection_reason
        return Response(data)

"""
Issuer Organization Profile Views
GET/PUT /api/issuer/organization/
POST    /api/issuer/organization/logo/
POST    /api/issuer/organization/seal/
GET/POST/DELETE /api/issuer/organization/members/
"""
from __future__ import annotations
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework import status
from rest_framework.permissions import IsAuthenticated
from rest_framework.parsers import MultiPartParser, FormParser, JSONParser
from django.shortcuts import get_object_or_404

from organizations.models import Organization, OrganizationMember


def _get_issuer_org(request):
    membership = OrganizationMember.objects.filter(
        user=request.user,
        role_in_org__in=['issuer_staff', 'manager'],
        is_active=True,
    ).select_related('organization').first()
    return membership.organization if membership else None


def _org_data(org) -> dict:
    from dids.models import DID
    did_string = None
    try:
        did_obj = DID.objects.filter(organization_did=org.organization_did).first()
        if did_obj:
            did_string = did_obj.did_string
        else:
            did_string = org.organization_did
    except Exception:
        did_string = org.organization_did

    member_count = OrganizationMember.objects.filter(organization=org, is_active=True).count()

    return {
        'id': str(org.id),
        'name': org.name,
        'organization_type': org.organization_type.name if org.organization_type else None,
        'status': org.status,
        'email': org.official_email,
        'phone': org.official_phone,
        'address': org.address,
        'website': org.website_url,
        'contact_person_name': org.contact_person_name if hasattr(org, 'contact_person_name') else '',
        'contact_person_email': org.contact_person_email if hasattr(org, 'contact_person_email') else '',
        'logo_url': org.logo_url,
        'seal_url': org.seal_url,
        'brand_color': org.brand_color,
        'did': did_string,
        'member_count': member_count,
        'issuer_status': org.issuer_status,
        'created_at': org.created_at.isoformat(),
    }


class IssuerOrganizationView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        return Response(_org_data(org))

    def put(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        org.name = request.data.get('name', org.name)
        org.official_phone = request.data.get('phone', org.official_phone)
        org.address = request.data.get('address', org.address)
        org.website_url = request.data.get('website', org.website_url)
        org.brand_color = request.data.get('brand_color', org.brand_color)
        if hasattr(org, 'contact_person_name'):
            org.contact_person_name = request.data.get('contact_person_name', org.contact_person_name)
            org.contact_person_email = request.data.get('contact_person_email', org.contact_person_email)
        org.save()
        return Response(_org_data(org))

    def patch(self, request):
        return self.put(request)


class IssuerOrganizationLogoView(APIView):
    permission_classes = [IsAuthenticated]
    parser_classes = [MultiPartParser, FormParser]

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        file = request.FILES.get('logo')
        if not file:
            return Response({'error': 'No logo file provided.'}, status=400)

        from django.core.files.storage import default_storage
        import os
        path = default_storage.save(f'logos/{org.id}/{file.name}', file)
        url = default_storage.url(path)
        org.logo_url = url
        org.save()
        return Response({'logo_url': url})


