class IssuerOrganizationMembersView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        members = OrganizationMember.objects.filter(
            organization=org, is_active=True
        ).select_related('user')

        data = []
        for m in members:
            u = m.user
            data.append({
                'id': str(u.id),
                'name': f"{u.first_name or ''} {u.last_name or ''}".strip() or u.email,
                'email': u.email,
                'role': m.role_in_org,
                'added_at': m.joined_at.isoformat() if m.joined_at else None,
            })
        return Response(data)

    def post(self, request):
        from django.contrib.auth import get_user_model
        User = get_user_model()
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        email = request.data.get('email', '').strip()
        role = request.data.get('role', 'issuer_staff')

        user = User.objects.filter(email=email).first()
        if not user:
            return Response({'error': f'No user found with email {email}.'}, status=404)

        _, created = OrganizationMember.objects.get_or_create(
            organization=org,
            user=user,
            defaults={'role_in_org': role, 'is_active': True}
        )
        if not created:
            return Response({'error': 'User is already a member of this organization.'}, status=400)

        return Response({'message': f'{email} added as {role}.'}, status=201)


class IssuerOrganizationMemberDetailView(APIView):
    permission_classes = [IsAuthenticated]

    def delete(self, request, user_id):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        member = OrganizationMember.objects.filter(
            organization=org, user_id=user_id
        ).first()
        if not member:
            return Response({'error': 'Member not found.'}, status=404)

        if str(member.user_id) == str(request.user.id):
            return Response({'error': 'You cannot remove yourself from the organization.'}, status=400)

        member.is_active = False
        member.save()
        return Response(status=204)

"""
Issuer API Config Views — federated member verification config
GET/POST /api/issuer/api-config/
POST     /api/issuer/api-config/test/
GET      /api/issuer/member-preview/
"""
from __future__ import annotations
import requests as http_requests
from django.utils import timezone
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated
from organizations.models import OrganizationMember
from issuer.models import IssuerApiConfig


def _get_issuer_org(request):
    membership = OrganizationMember.objects.filter(
        user=request.user,
        role_in_org__in=['issuer_staff', 'manager'],
        is_active=True,
    ).select_related('organization').first()
    return membership.organization if membership else None


def _config_data(cfg: IssuerApiConfig) -> dict:
    extra = cfg.response_extra_fields or {}
    extra_list = [{'response_field': k, 'claim_name': v} for k, v in extra.items()]
    return {
        'id': str(cfg.id),
        'api_base_url': cfg.api_base_url,
        'member_verify_endpoint': cfg.member_verify_endpoint,
        'api_key_header': cfg.api_key_header,
        'api_key_value': cfg.masked_api_key(),
        'request_id_field': cfg.request_id_field,
        'response_status_field': cfg.response_status_field,
        'response_name_field': cfg.response_name_field,
        'response_extra_fields': extra_list,
        'is_active': cfg.is_active,
        'last_tested_at': cfg.last_tested_at.isoformat() if cfg.last_tested_at else None,
        'last_test_result': cfg.last_test_result,
    }


class IssuerApiConfigView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        try:
            cfg = IssuerApiConfig.objects.get(organization=org)
            return Response(_config_data(cfg))
        except IssuerApiConfig.DoesNotExist:
            return Response(None, status=200)

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        data = request.data
        extra_list = data.get('response_extra_fields', [])
        if isinstance(extra_list, list):
            extra_dict = {row.get('response_field', ''): row.get('claim_name', '')
                         for row in extra_list if row.get('response_field')}
        else:
            extra_dict = extra_list if isinstance(extra_list, dict) else {}

        # Only update api_key_value if a new non-masked value is provided
        api_key_val = data.get('api_key_value', '')

        cfg, created = IssuerApiConfig.objects.get_or_create(
            organization=org,
            defaults={'api_key_value': api_key_val or ''}
        )

        cfg.api_base_url = data.get('api_base_url', cfg.api_base_url)
        cfg.member_verify_endpoint = data.get('member_verify_endpoint', cfg.member_verify_endpoint)
        cfg.api_key_header = data.get('api_key_header', cfg.api_key_header)
        # Only update the key if not masked
        if api_key_val and not api_key_val.startswith('****'):
            cfg.api_key_value = api_key_val
        cfg.request_id_field = data.get('request_id_field', cfg.request_id_field)
        cfg.response_status_field = data.get('response_status_field', cfg.response_status_field)
        cfg.response_name_field = data.get('response_name_field', cfg.response_name_field)
        cfg.response_extra_fields = extra_dict
        cfg.is_active = data.get('is_active', cfg.is_active)
        cfg.save()

        from audit.services import AuditService
        AuditService.log(
            user=request.user,
            action='api_config_updated',
            entity_type='IssuerApiConfig',
            entity_id=cfg.id,
        )

        return Response(_config_data(cfg), status=201 if created else 200)


class IssuerApiConfigTestView(APIView):
    permission_classes = [IsAuthenticated]

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        try:
            cfg = IssuerApiConfig.objects.get(organization=org)
        except IssuerApiConfig.DoesNotExist:
            return Response({'error': 'API configuration not found. Please save a configuration first.'}, status=404)

        test_member_id = request.data.get('test_member_id', '')
        if not test_member_id:
            return Response({'error': 'test_member_id is required.'}, status=400)

        url = cfg.api_base_url.rstrip('/') + '/' + cfg.member_verify_endpoint.lstrip('/')
        headers = {cfg.api_key_header: cfg.api_key_value}
        payload = {cfg.request_id_field: test_member_id}

        try:
            resp = http_requests.post(url, json=payload, headers=headers, timeout=10)
            success = resp.status_code == 200
            raw_response = resp.json() if resp.headers.get('content-type', '').startswith('application/json') else resp.text
        except http_requests.Timeout:
            cfg.last_tested_at = timezone.now()
            cfg.last_test_result = False
            cfg.save()
            return Response({
                'success': False,
                'error': 'Connection timed out after 10 seconds.',
            })
        except Exception as e:
            cfg.last_tested_at = timezone.now()
            cfg.last_test_result = False
            cfg.save()
            return Response({
                'success': False,
                'error': str(e),
            })

        cfg.last_tested_at = timezone.now()
        cfg.last_test_result = success
        cfg.save()

        from audit.services import AuditService
        AuditService.log(
            user=request.user,
            action='api_config_tested',
            entity_type='IssuerApiConfig',
            entity_id=cfg.id,
            metadata={'success': success, 'test_member_id': test_member_id},
        )

        return Response({
            'success': success,
            'status_code': resp.status_code,
            'raw_response': raw_response,
            'url_called': url,
        })


class MemberPreviewView(APIView):
    """GET /api/issuer/member-preview/?member_identifier=xxx"""
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        member_identifier = request.query_params.get('member_identifier', '').strip()
        if not member_identifier:
            return Response({'error': 'member_identifier is required.'}, status=400)

        from issuer.services import FederatedMemberService
        from issuer.services.federated_member_service import FederatedVerificationError

        try:
            result = FederatedMemberService.verify_member(org, member_identifier, actor=request.user)
            return Response({
                'found': True,
                'member_name': result.member_name,
                'extra_claims': result.extra_claims,
                'member_identifier': member_identifier,
            })
        except FederatedVerificationError as e:
            return Response({'found': False, 'error': str(e)}, status=400)

