Credential Type Views — under /api/issuer/credential-types/
"""
from __future__ import annotations
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated
from django.shortcuts import get_object_or_404
from credentials.models import CredentialType
from organizations.models import OrganizationMember
from audit.services import AuditService


def _get_issuer_org(request):
    m = OrganizationMember.objects.filter(
        user=request.user, role_in_org__in=['issuer_staff', 'manager'], is_active=True
    ).select_related('organization').first()
    return m.organization if m else None


def _type_data(ct, include_templates=False) -> dict:
    d = {
        'id': str(ct.id),
        'name': ct.name,
        'description': ct.description,
        'category': ct.allowed_organization_type or '',
        'is_active': ct.is_active,
        'created_at': ct.created_at.isoformat(),
    }
    if include_templates:
        from issuer.models import IssuanceTemplate
        templates = IssuanceTemplate.objects.filter(
            credential_type=ct
        ).values('id', 'name', 'version', 'is_active')
        d['templates'] = [
