def _get_issuer_org(request):
    m = OrganizationMember.objects.filter(
        user=request.user, role_in_org__in=['issuer_staff', 'manager'], is_active=True
    ).select_related('organization').first()
    return m.organization if m else None


def _tmpl_data(t: IssuanceTemplate) -> dict:
    return {
        'id': str(t.id),
        'name': t.name,
        'version': t.version,
        'credential_type': str(t.credential_type_id) if t.credential_type_id else None,
        'credential_type_name': t.credential_type.name if t.credential_type else None,
        'fields': t.fields,
        'svg_template': t.svg_template,
        'issuance_rules': t.issuance_rules,
        'is_active': t.is_active,
        'created_at': t.created_at.isoformat(),
    }


def _render_svg(svg: str, values: dict) -> str:
    result = str(svg)
    for key, val in values.items():
        if val is None:
            val = ''
        if isinstance(val, bool):
            val = 'Yes' if val else 'No'
        result = result.replace(f'{{{{{key}}}}}', str(val))
    return result


class IssuerTemplateListView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        templates = IssuanceTemplate.objects.filter(organization=org).order_by('name', '-version')
        return Response([_tmpl_data(t) for t in templates])

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        name = request.data.get('name', '').strip()
        if not name:
            return Response({'error': 'name is required.'}, status=400)

        credential_type = None
        ctype_id = request.data.get('credential_type_id')
        if ctype_id:
            from credentials.models import CredentialType
            try:
                credential_type = CredentialType.objects.get(id=ctype_id, issuing_organization=org)
            except CredentialType.DoesNotExist:
                return Response({'error': 'Credential type not found.'}, status=400)

        tmpl = IssuanceTemplate.objects.create(
            organization=org,
            credential_type=credential_type,
            name=name,
            version=1,
            fields=request.data.get('fields', []),
            svg_template=request.data.get('svg_template', ''),
            issuance_rules=request.data.get('issuance_rules', {}),
            is_active=True,
        )
