class IssuerTemplateDetailView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        t = get_object_or_404(IssuanceTemplate, id=pk, organization=org)
        return Response(_tmpl_data(t))

    def put(self, request, pk):
        """Create a new version of the template."""
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        old = get_object_or_404(IssuanceTemplate, id=pk, organization=org)

        # Deactivate old version
        old.is_active = False
        old.save()

        # Create new version
        new_version = old.version + 1
        new_tmpl = IssuanceTemplate.objects.create(
            organization=org,
            credential_type=old.credential_type,
            name=request.data.get('name', old.name),
            version=new_version,
            fields=request.data.get('fields', old.fields),
            svg_template=request.data.get('svg_template', old.svg_template),
            issuance_rules=request.data.get('issuance_rules', old.issuance_rules),
            is_active=True,
        )
        AuditService.log(user=request.user, action='template_versioned',
                         entity_type='IssuanceTemplate', entity_id=new_tmpl.id,
                         metadata={'previous_version': old.version, 'new_version': new_version})
        return Response(_tmpl_data(new_tmpl), status=201)

    def patch(self, request, pk):
        return self.put(request, pk)


