Issuance Views — federated credential issuance
POST /api/issuer/issue/
POST /api/issuer/issue/bulk/
GET  /api/issuer/issued/
GET  /api/issuer/issued/{id}/
POST /api/issuer/issued/{id}/revoke/
POST /api/issuer/issued/{id}/suspend/
POST /api/issuer/issued/{id}/reinstate/
"""
from __future__ import annotations
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated
from rest_framework.parsers import MultiPartParser, FormParser, JSONParser
from django.shortcuts import get_object_or_404
from django.utils import timezone

from organizations.models import OrganizationMember
from credentials.models import Credential
from audit.services import AuditService


def _get_issuer_org(request):
    m = OrganizationMember.objects.filter(
        user=request.user, role_in_org__in=['issuer_staff', 'manager'], is_active=True
    ).select_related('organization').first()
    return m.organization if m else None


def _cred_data(c: Credential, detail=False) -> dict:
    meta = c.render_metadata or {}
    d = {
        'id': str(c.id),
        'credential_type': c.credential_type.name if c.credential_type else None,
        'holder_name': meta.get('member_name', ''),
        'member_identifier': meta.get('member_identifier', ''),
        'status': c.status,
        'issued_at': c.issued_at.isoformat() if c.issued_at else None,
        'expires_at': c.expires_at.isoformat() if c.expires_at else None,
        'holder_did': c.holder_did,
        'issuer_did': c.issuer_did,
        'pending_holder_registration': meta.get('pending_holder_registration', False),
    }
    if detail:
        d['claims'] = meta.get('claims', {})
        d['credential_jwt'] = c.credential_jwt
        d['render_metadata'] = meta
        if c.wallet:
            try:
                u = c.wallet.user
                d['holder'] = {
                    'id': str(u.id),
                    'name': f"{u.first_name or ''} {u.last_name or ''}".strip() or u.email,
                    'email': u.email,
                    'national_id': u.national_id,
                }
            except Exception:
                pass
    return d


class IssuanceView(APIView):
    """POST /api/issuer/issue/"""
    permission_classes = [IsAuthenticated]

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        template_id = request.data.get('template_id')
        member_identifier = (request.data.get('member_identifier') or '').strip()
        manual_claims = request.data.get('manual_claims', {}) or {}

        if not template_id:
            return Response({'error': 'template_id is required.'}, status=400)
        if not member_identifier:
            return Response({'error': 'member_identifier is required.'}, status=400)

        # Check API is configured
        try:
            from issuer.models import IssuerApiConfig
            cfg = IssuerApiConfig.objects.get(organization=org)
            if not cfg.is_active:
                return Response({'error': 'The member verification API is disabled. Please enable it in API Configuration.'}, status=400)
        except Exception:
            return Response({'error': 'Please configure the member verification API before issuing credentials.'}, status=400)

        from issuer.services import FederatedIssuanceService
        from issuer.services.federated_member_service import FederatedVerificationError

        try:
            result = FederatedIssuanceService().issue(
                template_id=template_id,
                member_identifier=member_identifier,
                manual_claims=manual_claims,
                issuer_user=request.user,
                organization=org,
            )
            return Response(result, status=201)
        except FederatedVerificationError as e:
            return Response({'error': str(e)}, status=400)
        except Exception as e:
            return Response({'error': str(e)}, status=400)


class BulkIssuanceView(APIView):
    """POST /api/issuer/issue/bulk/"""
    permission_classes = [IsAuthenticated]
    parser_classes = [MultiPartParser, FormParser]

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        template_id = request.data.get('template_id')
        csv_file = request.FILES.get('csv_file') or request.FILES.get('file')

        if not template_id:
            return Response({'error': 'template_id is required.'}, status=400)
        if not csv_file:
            return Response({'error': 'A CSV file is required.'}, status=400)

        from issuer.services import FederatedIssuanceService
        try:
            result = FederatedIssuanceService().bulk_issue(
                template_id=template_id,
                csv_file=csv_file,
                issuer_user=request.user,
                organization=org,
            )
            return Response(result)
        except Exception as e:
            return Response({'error': str(e)}, status=400)


class IssuedCredentialsView(APIView):
    """GET /api/issuer/issued/"""
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        qs = Credential.objects.filter(organization=org).select_related('credential_type').order_by('-issued_at')

        status_filter = request.query_params.get('status')
        if status_filter:
            qs = qs.filter(status=status_filter)

        ctype_filter = request.query_params.get('credential_type')
        if ctype_filter:
            qs = qs.filter(credential_type__name__icontains=ctype_filter)

        search = request.query_params.get('search', '').strip()
        if search:
            qs = qs.filter(render_metadata__member_name__icontains=search) | \
                 qs.filter(render_metadata__member_identifier__icontains=search)

        # Pagination
        page_size = int(request.query_params.get('page_size', 50))
        page = int(request.query_params.get('page', 1))
        total = qs.count()
        offset = (page - 1) * page_size
        items = qs[offset:offset + page_size]

        return Response({
            'count': total,
            'results': [_cred_data(c) for c in items],
        })


