class RevokeCredentialView(APIView):
    """POST /api/issuer/issued/{id}/revoke/"""
    permission_classes = [IsAuthenticated]

    def post(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        c = get_object_or_404(Credential, id=pk, organization=org)
        reason = (request.data.get('reason') or '').strip()
        if not reason:
            return Response({'error': 'reason is required.'}, status=400)

        try:
            from credentials.services.revocation_service import RevocationService
            RevocationService.revoke_credential(c, revoked_by=request.user, reason=reason)
        except Exception:
            # Fallback: manual revoke
            c.status = Credential.Status.REVOKED
            meta = c.render_metadata or {}
            meta['revocation_reason'] = reason
            meta['revoked_at'] = timezone.now().isoformat()
            meta['revoked_by'] = str(request.user.id)
            # Bypass immutability guard on JWT by only updating status
            Credential.objects.filter(id=c.id).update(
                status=Credential.Status.REVOKED, render_metadata=meta
            )

        AuditService.log(user=request.user, action='credential_revoked',
                         entity_type='Credential', entity_id=c.id,
                         metadata={'reason': reason})
        return Response({'status': 'revoked', 'reason': reason})


class SuspendCredentialView(APIView):
    """POST /api/issuer/issued/{id}/suspend/"""
    permission_classes = [IsAuthenticated]

    def post(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        c = get_object_or_404(Credential, id=pk, organization=org)
        reason = (request.data.get('reason') or '').strip()
        if not reason:
            return Response({'error': 'reason is required.'}, status=400)

        meta = c.render_metadata or {}
        meta['suspended'] = True
        meta['suspension_reason'] = reason
        meta['suspended_at'] = timezone.now().isoformat()
        Credential.objects.filter(id=c.id).update(render_metadata=meta)

        AuditService.log(user=request.user, action='credential_suspended',
                         entity_type='Credential', entity_id=c.id,
                         metadata={'reason': reason})
        return Response({'status': 'suspended', 'reason': reason})


class ReinstateCredentialView(APIView):
    """POST /api/issuer/issued/{id}/reinstate/"""
    permission_classes = [IsAuthenticated]

    def post(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        c = get_object_or_404(Credential, id=pk, organization=org)
        meta = c.render_metadata or {}
        meta['suspended'] = False
        meta['reinstated_at'] = timezone.now().isoformat()
        Credential.objects.filter(id=c.id).update(render_metadata=meta)

        if c.status == Credential.Status.REVOKED:
            # Reinstate from revoke
            Credential.objects.filter(id=c.id).update(status=Credential.Status.ACTIVE)

        AuditService.log(user=request.user, action='credential_reinstated',
                         entity_type='Credential', entity_id=c.id)
        return Response({'status': 'reinstated'})

