def _get_issuer_org(request):
    m = OrganizationMember.objects.filter(
        user=request.user, role_in_org__in=['issuer_staff', 'manager'], is_active=True
    ).select_related('organization').first()
    return m.organization if m else None


def _req_data(r: CredentialRequest, detail=False) -> dict:
    holder = r.holder
    d = {
        'id': str(r.id),
        'credential_type': r.credential_type.name if r.credential_type else None,
        'holder_name': f"{holder.first_name or ''} {holder.last_name or ''}".strip() or holder.email,
        'holder_email': holder.email,
        'holder_national_id': holder.national_id,
        'status': r.status,
        'created_at': r.created_at.isoformat() if hasattr(r, 'created_at') and r.created_at else None,
        'requested_claims': {**(r.identity_claims or {}), **(r.additional_claims or {})},
    }
    if detail:
        d['credential'] = str(r.credential_id) if r.credential_id else None
        d['rejection_reason'] = r.rejection_reason if hasattr(r, 'rejection_reason') else None
    return d


