class IssuerRequestApproveView(APIView):
    permission_classes = [IsAuthenticated]

    def post(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        r = get_object_or_404(CredentialRequest, id=pk, organization=org)
        if r.status != CredentialRequest.Status.PENDING:
            return Response({'error': f'Request is already {r.status}.'}, status=400)

        holder = r.holder
        member_identifier = holder.national_id
        if not member_identifier:
            return Response({
                'error': 'The holder does not have a national ID registered. Cannot verify membership.'
            }, status=400)

        # Find active template for this credential type
        from issuer.models import IssuanceTemplate
        template = IssuanceTemplate.objects.filter(
            organization=org,
            credential_type=r.credential_type,
            is_active=True
        ).first()

        if not template:
            # Try any active template for the org
            template = IssuanceTemplate.objects.filter(
                organization=org, is_active=True
            ).first()

        if not template:
            return Response({'error': 'No active issuance template found for this credential type.'}, status=400)

        from issuer.services import FederatedIssuanceService
        from issuer.services.federated_member_service import FederatedVerificationError

        manual_claims = {**(r.additional_claims or {})}

        try:
            result = FederatedIssuanceService().issue(
                template_id=str(template.id),
                member_identifier=member_identifier,
                manual_claims=manual_claims,
                issuer_user=request.user,
                organization=org,
            )
            r.status = CredentialRequest.Status.ISSUED
            r.reviewed_by = request.user
            r.save()

            AuditService.log(user=request.user, action='request_approved',
                             entity_type='CredentialRequest', entity_id=r.id)
            return Response({'status': 'approved', 'credential': result})
        except FederatedVerificationError as e:
            AuditService.log(user=request.user, action='request_approval_failed_federated',
                             entity_type='CredentialRequest', entity_id=r.id,
                             metadata={'reason': str(e)})
            return Response({
                'error': str(e),
                'status': 'federated_verification_failed',
            }, status=400)
        except Exception as e:
            return Response({'error': str(e)}, status=400)


class IssuerRequestRejectView(APIView):
    permission_classes = [IsAuthenticated]

    def post(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        r = get_object_or_404(CredentialRequest, id=pk, organization=org)
        reason = (request.data.get('reason') or '').strip()
        if not reason:
            return Response({'error': 'reason is required.'}, status=400)

        r.status = CredentialRequest.Status.REJECTED
        r.reviewed_by = request.user
        if hasattr(r, 'rejection_reason'):
            r.rejection_reason = reason
        r.save()

        AuditService.log(user=request.user, action='request_rejected',
                         entity_type='CredentialRequest', entity_id=r.id,
                         metadata={'reason': reason})
        return Response({'status': 'rejected', 'reason': reason})


class IssuerRequestBulkApproveView(APIView):
    permission_classes = [IsAuthenticated]

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        request_ids = request.data.get('request_ids', [])
        results = {'approved': [], 'failed': []}

        for rid in request_ids:
            try:
                r = CredentialRequest.objects.get(id=rid, organization=org)
                if r.status != CredentialRequest.Status.PENDING:
                    results['failed'].append({'id': rid, 'reason': f'Already {r.status}'})
                    continue

                from issuer.services import FederatedIssuanceService
                from issuer.services.federated_member_service import FederatedVerificationError
                from issuer.models import IssuanceTemplate

                template = IssuanceTemplate.objects.filter(
                    organization=org,
                    credential_type=r.credential_type,
                    is_active=True
                ).first()

                if not template:
                    results['failed'].append({'id': rid, 'reason': 'No active template'})
                    continue

                member_id = r.holder.national_id
                if not member_id:
                    results['failed'].append({'id': rid, 'reason': 'Holder has no national ID'})
                    continue

                FederatedIssuanceService().issue(
                    template_id=str(template.id),
                    member_identifier=member_id,
                    manual_claims=r.additional_claims or {},
                    issuer_user=request.user,
                    organization=org,
                )
                r.status = CredentialRequest.Status.ISSUED
                r.save()
                results['approved'].append(rid)
            except Exception as e:
                results['failed'].append({'id': rid, 'reason': str(e)})

        return Response(results)


class IssuerRequestBulkRejectView(APIView):
    permission_classes = [IsAuthenticated]

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        request_ids = request.data.get('request_ids', [])
        reason = (request.data.get('reason') or 'Bulk rejected').strip()

        rejected = []
        for rid in request_ids:
            try:
                r = CredentialRequest.objects.get(id=rid, organization=org)
                r.status = CredentialRequest.Status.REJECTED
                r.reviewed_by = request.user
                if hasattr(r, 'rejection_reason'):
                    r.rejection_reason = reason
                r.save()
                rejected.append(rid)
            except Exception:
                pass

        return Response({'rejected': rejected, 'reason': reason})

