class IssuerAnalyticsStatsView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        stats = IssuerStatsService.get_dashboard(org)
        # Month-over-month change
        from credentials.models import Credential
        from django.utils import timezone
        now = timezone.now()
        this_month = Credential.objects.filter(
            organization=org,
            issued_at__year=now.year,
            issued_at__month=now.month,
        ).count()
        last_month_date = (now.replace(day=1) - timedelta(days=1))
        last_month = Credential.objects.filter(
            organization=org,
            issued_at__year=last_month_date.year,
            issued_at__month=last_month_date.month,
        ).count()
        if last_month > 0:
            mom = round((this_month - last_month) / last_month * 100, 1)
        else:
            mom = 100.0 if this_month > 0 else 0.0
        stats['month_over_month_change'] = mom
        return Response(stats)


