        today = date.today()
        try:
            start_date = date.fromisoformat(request.query_params.get('start_date', str(today - timedelta(days=30))))
            end_date = date.fromisoformat(request.query_params.get('end_date', str(today)))
        except ValueError:
            start_date = today - timedelta(days=30)
            end_date = today
        return Response(IssuerStatsService.get_trends(org, start_date, end_date))


