Signatory Views — under /api/issuer/signatories/ (using existing implementations)
"""
from __future__ import annotations
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated
from django.shortcuts import get_object_or_404
from organizations.models import OrganizationMember, Signatory
from audit.services import AuditService


def _get_issuer_org(request):
    m = OrganizationMember.objects.filter(
        user=request.user, role_in_org__in=['issuer_staff', 'manager'], is_active=True
    ).select_related('organization').first()
    return m.organization if m else None


def _sig_data(s: Signatory) -> dict:
    return {
        'id': str(s.id),
        'name': s.name,
        'title': s.title,
        'is_active': s.is_active if hasattr(s, 'is_active') else True,
        'signature_url': s.signature_url if hasattr(s, 'signature_url') else None,
        'created_at': s.created_at.isoformat() if hasattr(s, 'created_at') and s.created_at else None,
    }


class IssuerSignatoriesView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        sigs = Signatory.objects.filter(organization=org)
        return Response([_sig_data(s) for s in sigs])

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        name = (request.data.get('name') or '').strip()
        title = (request.data.get('title') or '').strip()
        if not name:
            return Response({'error': 'name is required.'}, status=400)

        sig = Signatory(organization=org, name=name, title=title)
        if hasattr(sig, 'is_active'):
            sig.is_active = True
        if hasattr(sig, 'signature_url'):
            sig.signature_url = request.data.get('signature_url', '') or ''
        sig.save()

        AuditService.log(user=request.user, action='signatory_created',
                         entity_type='Signatory', entity_id=sig.id)
        return Response(_sig_data(sig), status=201)


class IssuerSignatoryDetailView(APIView):
    permission_classes = [IsAuthenticated]

    def delete(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        sig = get_object_or_404(Signatory, id=pk, organization=org)

        if hasattr(sig, 'is_active'):
            sig.is_active = False
            sig.save()
        else:
            sig.delete()

        AuditService.log(user=request.user, action='signatory_deactivated',
                         entity_type='Signatory', entity_id=sig.id)
        return Response(status=204)

