import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { getTemplates, getTemplate, issueCredential, getMemberPreview } from '../../api/issuer';
import Select from '../../components/common/Select';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import toast from 'react-hot-toast';
import { Search, CheckCircle2, AlertCircle, User, Send } from 'lucide-react';

export default function IssuancePage() {
  const navigate = useNavigate();
  const [templates, setTemplates] = useState([]);
  const [selectedTemplateId, setSelectedTemplateId] = useState('');
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [loadingTemplate, setLoadingTemplate] = useState(false);
  const [issuing, setIssuing] = useState(false);
  const [memberIdentifier, setMemberIdentifier] = useState('');
  const [memberInfo, setMemberInfo] = useState(null);
  const [memberLookupLoading, setMemberLookupLoading] = useState(false);
  const [memberError, setMemberError] = useState('');
  const { register, handleSubmit, formState: { errors } } = useForm();

  useEffect(() => {
    getTemplates({ is_active: true })
      .then((r) => setTemplates(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!selectedTemplateId) { setSelectedTemplate(null); return; }
    setLoadingTemplate(true);
    getTemplate(selectedTemplateId)
      .then((r) => setSelectedTemplate(r.data))
      .catch(() => {})
      .finally(() => setLoadingTemplate(false));
  }, [selectedTemplateId]);

  const handleMemberLookup = async () => {
    if (!memberIdentifier.trim()) {
      toast.error('Enter a member identifier to look up');
      return;
    }
    setMemberLookupLoading(true);
    setMemberInfo(null);
    setMemberError('');
    try {
      const res = await getMemberPreview({ member_identifier: memberIdentifier.trim() });
      if (res.data.found) {
        setMemberInfo(res.data);
        toast.success('Member verified successfully');
      } else {
        setMemberError(res.data.error || 'Member not found');
        toast.error('Member not found in organization system');
      }
    } catch (err) {
      const errMsg = err.response?.data?.error || err.response?.data?.detail || 'Member lookup failed';
      setMemberError(errMsg);
      toast.error(errMsg);
    } finally { setMemberLookupLoading(false); }
  };

  const onSubmit = async (data) => {
    if (!selectedTemplateId) { toast.error('Please select a template'); return; }
    if (!memberIdentifier.trim()) { toast.error('Please enter a member identifier'); return; }
    setIssuing(true);
    try {
      const manualFields = selectedTemplate?.fields?.filter(f => f.source === 'manual') || [];
      const manualClaims = {};
      for (const f of manualFields) {
        if (data[`field_${f.name}`]) {
          manualClaims[f.name] = data[`field_${f.name}`];
        }
      }
      await issueCredential({
        template_id: selectedTemplateId,
        member_identifier: memberIdentifier.trim(),
        manual_claims: manualClaims,
      });
      toast.success('Credential issued successfully');
      navigate('/issuer/issued');
    } catch (err) {
      toast.error(err.response?.data?.error || err.response?.data?.detail || 'Issuance failed');
    } finally { setIssuing(false); }
  };

  const manualFields = selectedTemplate?.fields?.filter(f => f.source === 'manual') || [];

  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <h1 className="text-2xl font-bold text-foreground">Issue Credential</h1>
        <p className="text-muted-foreground text-sm mt-1">
          Verify member via your organization's system and issue a credential.
        </p>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
        {/* Template Selection */}
        <div className="card p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">1. Select Template</h2>
          <Select
            label="Issuance Template"
            value={selectedTemplateId}
            onChange={(e) => setSelectedTemplateId(e.target.value)}
            required
          >
            <option value="">— Choose template —</option>
            {templates.map((t) => (
              <option key={t.id} value={t.id}>{t.name} {t.version ? `(v${t.version})` : ''}</option>
            ))}
          </Select>
          {loadingTemplate && <CardSkeleton />}
          {selectedTemplate && (
            <div className="bg-muted/40 rounded p-3 text-xs text-muted-foreground space-y-1">
              <p><strong>Fields:</strong> {(selectedTemplate.fields || []).length} defined</p>
              {selectedTemplate.issuance_rules?.expiry_days && (
                <p><strong>Validity:</strong> {selectedTemplate.issuance_rules.expiry_days} days</p>
              )}
            </div>
          )}
        </div>

        {/* Member Verification */}
        <div className="card p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">2. Verify Member</h2>
          <p className="text-xs text-muted-foreground">
            Enter the member's national ID or membership number to verify them against your organization's system.
          </p>
          <div className="flex gap-2">
            <div className="flex-1">
              <Input
                label="Member Identifier (National ID / Membership No.)"
                value={memberIdentifier}
                onChange={(e) => { setMemberIdentifier(e.target.value); setMemberInfo(null); setMemberError(''); }}
                placeholder="e.g. NID-1234567890"
              />
            </div>
            <div className="pt-6">
              <Button
                type="button"
                variant="outline"
                onClick={handleMemberLookup}
                isLoading={memberLookupLoading}
              >
                <Search className="h-4 w-4 mr-1" /> Verify
              </Button>
            </div>
          </div>

          {memberInfo?.found && (
            <div className="flex items-start gap-3 p-3 rounded bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800">
              <CheckCircle2 className="h-5 w-5 text-green-500 mt-0.5 flex-shrink-0" />
              <div>
                <p className="text-sm font-medium text-green-800 dark:text-green-200">{memberInfo.member_name || 'Member Verified'}</p>
                <p className="text-xs text-green-700 dark:text-green-300">Active member confirmed in organization system</p>
                {Object.keys(memberInfo.extra_claims || {}).length > 0 && (
                  <div className="mt-2 space-y-0.5">
                    {Object.entries(memberInfo.extra_claims).map(([k, v]) => (
                      <p key={k} className="text-xs text-green-700 dark:text-green-300">
                        <strong>{k}:</strong> {String(v)}
                      </p>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {memberError && (
            <div className="flex items-start gap-3 p-3 rounded bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800">
              <AlertCircle className="h-5 w-5 text-red-500 mt-0.5 flex-shrink-0" />
              <p className="text-sm text-red-700 dark:text-red-300">{memberError}</p>
            </div>
          )}
        </div>

        {/* Manual Fields */}
        {manualFields.length > 0 && (
          <div className="card p-6 space-y-4">
            <h2 className="text-sm font-semibold text-foreground">3. Manual Fields</h2>
            <p className="text-xs text-muted-foreground">
              These fields must be entered manually (not sourced from the member API).
            </p>
            {manualFields.map((f) => (
              <Input
                key={f.name}
                label={f.label || f.name}
                {...register(`field_${f.name}`, { required: f.required ? `${f.label || f.name} is required` : false })}
                error={errors[`field_${f.name}`]?.message}
                placeholder={f.default_value || ''}
              />
            ))}
          </div>
        )}

        <Button
          type="submit"
          isLoading={issuing}
          disabled={!selectedTemplateId || !memberIdentifier.trim()}
          className="w-full"
        >
          <Send className="h-4 w-4 mr-2" />
          Issue Credential
        </Button>
      </form>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getTemplates, bulkIssueCredentials } from '../../api/issuer';
import Select from '../../components/common/Select';
import Button from '../../components/common/Button';
import FileUpload from '../../components/common/FileUpload';
import Table from '../../components/common/Table';
import { CheckCircle, XCircle, Download, UploadCloud } from 'lucide-react';
import toast from 'react-hot-toast';

const SAMPLE_CSV = `member_identifier,note
NID-1234567890,Engineering graduate
NID-0987654321,Science graduate
`;

export default function BulkIssuancePage() {
  const navigate = useNavigate();
  const [templates, setTemplates] = useState([]);
  const [selectedTemplate, setSelectedTemplate] = useState('');
  const [files, setFiles] = useState([]);
  const [issuing, setIssuing] = useState(false);
  const [result, setResult] = useState(null);

  useEffect(() => {
    getTemplates({ is_active: true })
      .then((r) => setTemplates(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  const downloadSample = () => {
    const blob = new Blob([SAMPLE_CSV], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'bulk_issuance_template.csv';
    a.click();
  };

  const handleIssue = async () => {
    if (!selectedTemplate) { toast.error('Please select a template'); return; }
    if (!files.length) { toast.error('Please upload a CSV file'); return; }
    setIssuing(true);
    setResult(null);
    const fd = new FormData();
    fd.append('template_id', selectedTemplate);
    fd.append('csv_file', files[0]);
    try {
      const res = await bulkIssueCredentials(fd);
      setResult(res.data);
      if (res.data.issued > 0) {
        toast.success(`${res.data.issued} credential(s) issued successfully`);
      }
      if (res.data.failed_count > 0) {
        toast.error(`${res.data.failed_count} credential(s) failed`);
      }
    } catch (err) {
      toast.error(err.response?.data?.error || err.response?.data?.detail || 'Bulk issuance failed');
    } finally { setIssuing(false); }
  };

  const failureColumns = [
    { key: 'member_identifier', label: 'Member ID' },
    { key: 'reason', label: 'Failure Reason', render: (v) => <span className="text-xs text-red-500">{v}</span> },
  ];

  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <h1 className="text-2xl font-bold text-foreground">Bulk Issuance</h1>
        <p className="text-muted-foreground text-sm mt-1">
          Issue credentials to multiple members at once by uploading a CSV file.
          Each member is verified against your organization's member API.
        </p>
      </div>

      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground">Configuration</h2>

        <Select
          label="Issuance Template"
          value={selectedTemplate}
          onChange={(e) => setSelectedTemplate(e.target.value)}
          required
        >
          <option value="">— Choose template —</option>
          {templates.map((t) => (
            <option key={t.id} value={t.id}>{t.name}</option>
          ))}
        </Select>

        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <label className="text-sm font-medium text-foreground">CSV File</label>
            <Button type="button" variant="ghost" size="sm" onClick={downloadSample}>
              <Download className="h-4 w-4 mr-1" /> Download Sample
            </Button>
          </div>
          <FileUpload
            accept=".csv"
            maxFiles={1}
            onFilesChange={setFiles}
          />
          <p className="text-xs text-muted-foreground">
            CSV must include a <code className="bg-muted px-1 rounded">member_identifier</code> column with
            the national ID / membership number of each recipient.
          </p>
        </div>

        <div className="flex gap-3 pt-2">
          <Button
            onClick={handleIssue}
            isLoading={issuing}
            disabled={!selectedTemplate || !files.length}
            className="flex-1"
          >
            <UploadCloud className="h-4 w-4 mr-2" />
            {issuing ? 'Issuing...' : 'Issue All'}
          </Button>
        </div>
      </div>

      {result && (
        <div className="space-y-4">
          <div className="grid grid-cols-3 gap-4">
            {[
              { label: 'Total Rows', value: result.total, color: 'text-foreground' },
              { label: 'Issued', value: result.issued, color: 'text-green-600' },
              { label: 'Failed', value: result.failed_count, color: 'text-red-500' },
            ].map((s) => (
              <div key={s.label} className="card p-4 text-center">
                <p className={`text-2xl font-bold ${s.color}`}>{s.value}</p>
                <p className="text-xs text-muted-foreground mt-1">{s.label}</p>
              </div>
            ))}
          </div>

          {result.failures?.length > 0 && (
            <div className="card p-4 space-y-3">
              <h3 className="text-sm font-semibold text-foreground">Failed Rows</h3>
              <Table
                columns={failureColumns}
                data={result.failures}
                emptyMessage="No failures"
              />
            </div>
          )}

          {result.issued > 0 && (
            <Button variant="outline" onClick={() => navigate('/issuer/issued')} className="w-full">
              View Issued Credentials
            </Button>
          )}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useForm, useFieldArray } from 'react-hook-form';
import { getApiConfig, saveApiConfig, testApiConfig, getMemberPreview } from '../../api/issuer';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import toast from 'react-hot-toast';
import { Plug, Plus, Trash2, CheckCircle2, XCircle, Search } from 'lucide-react';

export default function ApiConfigPage() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState(null);
  const [previewId, setPreviewId] = useState('');
  const [previewLoading, setPreviewLoading] = useState(false);
  const [previewResult, setPreviewResult] = useState(null);

  const { register, handleSubmit, control, reset, formState: { errors } } = useForm({
    defaultValues: {
      api_base_url: '',
      member_verify_endpoint: '/api/members/verify',
      api_key_header: 'X-API-Key',
      api_key_value: '',
      request_id_field: 'national_id',
      response_status_field: 'is_active',
      response_name_field: 'full_name',
      response_extra_fields: [],
    },
  });

  const { fields, append, remove } = useFieldArray({ control, name: 'response_extra_fields' });

  const [testMemberId, setTestMemberId] = useState('');

  useEffect(() => {
    getApiConfig()
      .then((r) => {
        if (r.data) reset({
          api_base_url: r.data.api_base_url || '',
          member_verify_endpoint: r.data.member_verify_endpoint || '/api/members/verify',
          api_key_header: r.data.api_key_header || 'X-API-Key',
          api_key_value: r.data.api_key_value || '',
          request_id_field: r.data.request_id_field || 'national_id',
          response_status_field: r.data.response_status_field || 'is_active',
          response_name_field: r.data.response_name_field || 'full_name',
          response_extra_fields: r.data.response_extra_fields || [],
        });
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const onSubmit = async (data) => {
    setSaving(true);
    try {
      await saveApiConfig(data);
      toast.success('API configuration saved successfully');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to save API configuration');
    } finally { setSaving(false); }
  };

  const handleTest = async () => {
    if (!testMemberId.trim()) { toast.error('Enter a test member ID'); return; }
    setTesting(true);
    setTestResult(null);
    try {
      const res = await testApiConfig({ test_member_id: testMemberId.trim() });
      setTestResult(res.data);
      if (res.data.success) {
        toast.success('API connection test passed!');
      } else {
        toast.error('API connection test failed');
      }
    } catch (err) {
      setTestResult({ success: false, error: err.response?.data?.error || 'Connection test failed' });
      toast.error('API connection test failed');
    } finally { setTesting(false); }
  };

  const handlePreview = async () => {
    if (!previewId.trim()) { toast.error('Enter a member ID to preview'); return; }
    setPreviewLoading(true);
    setPreviewResult(null);
    try {
      const res = await getMemberPreview({ member_identifier: previewId.trim() });
      setPreviewResult(res.data);
      if (res.data.found) toast.success('Member found!');
      else toast.error('Member not found');
    } catch (err) {
      setPreviewResult({ found: false, error: err.response?.data?.error || 'Preview failed' });
    } finally { setPreviewLoading(false); }
  };

  if (loading) return <CardSkeleton />;

  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
          <Plug className="h-6 w-6" /> Member API Configuration
        </h1>
        <p className="text-muted-foreground text-sm mt-1">
          Configure the external API that verifies your members before credential issuance.
        </p>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
        {/* Connection */}
        <div className="card p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">Connection Settings</h2>
          <Input
            label="API Base URL"
            {...register('api_base_url', { required: 'API base URL is required' })}
            error={errors.api_base_url?.message}
            placeholder="https://api.yourorg.edu"
          />
          <Input
            label="Verify Endpoint Path"
            {...register('member_verify_endpoint')}
            placeholder="/api/members/verify"
            hint="Appended to the base URL. E.g. /api/members/verify"
          />
          <div className="grid grid-cols-2 gap-4">
            <Input
              label="API Key Header Name"
              {...register('api_key_header')}
              placeholder="X-API-Key"
            />
            <Input
              label="API Key Value"
              type="password"
              {...register('api_key_value')}
              placeholder="Enter new key to update"
              hint="Leave as-is to keep existing key"
            />
          </div>
        </div>

        {/* Field Mapping */}
        <div className="card p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">Request & Response Mapping</h2>
          <Input
            label="Member Identifier Field (in request body)"
            {...register('request_id_field')}
            placeholder="national_id"
            hint="This is the field name sent to your API, e.g. national_id"
          />
          <div className="grid grid-cols-2 gap-4">
            <Input
              label="Membership Status Field (in response)"
              {...register('response_status_field')}
              placeholder="is_active"
            />
            <Input
              label="Member Name Field (in response)"
              {...register('response_name_field')}
              placeholder="full_name"
            />
          </div>

          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <label className="text-sm font-medium text-foreground">Extra Field Mappings</label>
              <Button type="button" size="sm" variant="outline"
                onClick={() => append({ response_field: '', claim_name: '' })}>
                <Plus className="h-3 w-3 mr-1" /> Add
              </Button>
            </div>
            <p className="text-xs text-muted-foreground">
              Map additional response fields to credential claim names.
            </p>
            {fields.length === 0 && (
              <p className="text-xs text-muted-foreground italic">No extra fields configured.</p>
            )}
            {fields.map((field, index) => (
              <div key={field.id} className="flex gap-2 items-end">
                <div className="flex-1">
                  <Input
                    label="Response field"
                    {...register(`response_extra_fields.${index}.response_field`)}
                    placeholder="student_id"
                  />
                </div>
                <div className="flex-1">
                  <Input
                    label="Claim name"
                    {...register(`response_extra_fields.${index}.claim_name`)}
                    placeholder="studentId"
                  />
                </div>
                <Button type="button" variant="ghost" size="sm" className="pb-0 text-red-500"
                  onClick={() => remove(index)}>
                  <Trash2 className="h-4 w-4" />
                </Button>
              </div>
            ))}
          </div>
        </div>

        <Button type="submit" isLoading={saving} className="w-full">
          Save Configuration
        </Button>
      </form>

      {/* Test Connection */}
      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground">Test Connection</h2>
        <p className="text-xs text-muted-foreground">
          Send a test request to your member API to verify the configuration is correct.
        </p>
        <div className="flex gap-2">
          <div className="flex-1">
            <Input
              label="Test Member ID"
              value={testMemberId}
              onChange={(e) => setTestMemberId(e.target.value)}
              placeholder="Enter a real member ID for testing"
            />
          </div>
          <div className="pt-6">
            <Button type="button" variant="outline" onClick={handleTest} isLoading={testing}>
              Test
            </Button>
          </div>
        </div>
        {testResult && (
          <div className={`p-3 rounded border text-sm ${testResult.success ? 'bg-green-50 dark:bg-green-900/20 border-green-200 text-green-800 dark:text-green-200' : 'bg-red-50 dark:bg-red-900/20 border-red-200 text-red-700 dark:text-red-300'}`}>
            <div className="flex items-center gap-2 font-medium mb-1">
              {testResult.success ? <CheckCircle2 className="h-4 w-4" /> : <XCircle className="h-4 w-4" />}
              {testResult.success ? 'Connection successful' : 'Connection failed'}
            </div>
            {testResult.error && <p className="text-xs">{testResult.error}</p>}
            {testResult.status_code && <p className="text-xs">HTTP {testResult.status_code}</p>}
            {testResult.raw_response && (
              <pre className="mt-2 text-xs bg-black/5 rounded p-2 overflow-auto max-h-32">
                {JSON.stringify(testResult.raw_response, null, 2)}
              </pre>
            )}
          </div>
        )}
      </div>

      {/* Member Preview */}
      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground">Member Preview</h2>
        <p className="text-xs text-muted-foreground">
          Look up how a specific member will appear before issuing a credential.
        </p>
        <div className="flex gap-2">
          <div className="flex-1">
            <Input
              label="Member Identifier"
              value={previewId}
              onChange={(e) => setPreviewId(e.target.value)}
              placeholder="National ID / Membership No."
            />
          </div>
          <div className="pt-6">
            <Button type="button" variant="outline" onClick={handlePreview} isLoading={previewLoading}>
              <Search className="h-4 w-4 mr-1" /> Preview
            </Button>
          </div>
        </div>
        {previewResult && (
          <div className={`p-3 rounded border text-sm ${previewResult.found ? 'bg-green-50 dark:bg-green-900/20 border-green-200' : 'bg-red-50 dark:bg-red-900/20 border-red-200'}`}>
            {previewResult.found ? (
              <div className="space-y-1">
                <p className="font-medium text-green-800 dark:text-green-200">{previewResult.member_name}</p>
                {Object.entries(previewResult.extra_claims || {}).map(([k, v]) => (
                  <p key={k} className="text-xs text-green-700 dark:text-green-300">
                    <strong>{k}:</strong> {String(v)}
                  </p>
                ))}
              </div>
            ) : (
              <p className="text-red-700 dark:text-red-300">{previewResult.error || 'Member not found'}</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { BadgeCheck, FileText, Send, ClipboardList, AlertTriangle, Users, Plug } from 'lucide-react';
import { getIssuerDashboard, getIssuedCredentials } from '../../api/issuer';
