import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { BadgeCheck, FileText, Send, ClipboardList, AlertTriangle, Users, Plug } from 'lucide-react';
import { getIssuerDashboard, getIssuedCredentials } from '../../api/issuer';
import { StatusBadge } from '../../components/common/Badge';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';

export default function IssuerDashboard() {
  const [stats, setStats] = useState(null);
  const [recent, setRecent] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      getIssuerDashboard(),
      getIssuedCredentials({ page_size: 5 }),
    ]).then(([dash, creds]) => {
      setStats(dash.data);
      setRecent(creds.data?.results || creds.data || []);
    }).catch(() => {}).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="space-y-4"><CardSkeleton /><CardSkeleton /></div>;

  const statCards = [
    { label: 'Total Issued', value: stats?.total_issued ?? 0, icon: BadgeCheck, color: 'text-blue-600', bg: 'bg-blue-50 dark:bg-blue-900/20', href: '/issuer/issued' },
    { label: 'Active', value: stats?.active_count ?? 0, icon: BadgeCheck, color: 'text-green-600', bg: 'bg-green-50 dark:bg-green-900/20', href: '/issuer/issued?status=active' },
    { label: 'Pending Requests', value: stats?.pending_requests_count ?? 0, icon: ClipboardList, color: 'text-yellow-600', bg: 'bg-yellow-50 dark:bg-yellow-900/20', href: '/issuer/requests' },
    { label: 'Templates', value: stats?.active_templates_count ?? 0, icon: FileText, color: 'text-purple-600', bg: 'bg-purple-50 dark:bg-purple-900/20', href: '/issuer/templates' },
    { label: 'Revoked', value: stats?.revoked_count ?? 0, icon: AlertTriangle, color: 'text-red-500', bg: 'bg-red-50 dark:bg-red-900/20', href: '/issuer/issued?status=revoked' },
    { label: 'Awaiting Wallet', value: stats?.pending_holder_registrations_count ?? 0, icon: Users, color: 'text-orange-500', bg: 'bg-orange-50 dark:bg-orange-900/20', href: '/issuer/issued' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Issuer Dashboard</h1>
          <p className="text-muted-foreground text-sm mt-1">Overview of your credential issuance activity.</p>
        </div>
        <div className="flex gap-2">
          {!stats?.api_config_connected && (
            <Link to="/issuer/api-config">
              <div className="flex items-center gap-1 text-xs bg-yellow-100 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-300 px-3 py-1.5 rounded-full border border-yellow-200 dark:border-yellow-700">
                <Plug className="h-3 w-3" /> API not configured
              </div>
            </Link>
          )}
          <Link to="/issuer/issue">
            <button className="btn-primary text-sm px-4 py-2 rounded-lg flex items-center gap-2">
              <Send className="h-4 w-4" /> Issue Credential
            </button>
          </Link>
        </div>
      </div>

      {!stats?.api_config_connected && (
        <div className="card border-yellow-200 dark:border-yellow-700 bg-yellow-50/50 dark:bg-yellow-900/10 p-4">
          <div className="flex items-start gap-3">
            <Plug className="h-5 w-5 text-yellow-600 mt-0.5" />
            <div>
              <p className="text-sm font-medium text-yellow-800 dark:text-yellow-200">Member API not connected</p>
              <p className="text-xs text-yellow-700 dark:text-yellow-300 mt-0.5">
                Configure your organization's member verification API to enable credential issuance.
              </p>
              <Link to="/issuer/api-config" className="text-xs text-yellow-700 dark:text-yellow-300 underline mt-1 inline-block">
                Set up API config →
              </Link>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-6 gap-4">
        {statCards.map((s) => (
          <Link key={s.label} to={s.href} className="card p-4 hover:shadow-md transition-shadow">
            <div className={`inline-flex p-2 rounded-lg ${s.bg} mb-3`}>
              <s.icon className={`h-4 w-4 ${s.color}`} />
            </div>
            <p className="text-xl font-bold text-foreground">{s.value}</p>
            <p className="text-xs text-muted-foreground mt-0.5">{s.label}</p>
          </Link>
        ))}
      </div>

      <div className="card p-6">
        <div className="flex items-center justify-between mb-4">
          <h2 className="font-semibold text-foreground">Recent Credentials</h2>
          <Link to="/issuer/issued" className="text-sm text-primary hover:underline">View all →</Link>
        </div>
        {recent.length === 0 ? (
          <div className="text-center py-8">
            <BadgeCheck className="h-10 w-10 text-muted-foreground/30 mx-auto mb-2" />
            <p className="text-sm text-muted-foreground">No credentials issued yet.</p>
            <Link to="/issuer/issue" className="text-sm text-primary hover:underline mt-1 inline-block">
              Issue your first credential →
            </Link>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="text-left text-xs text-muted-foreground border-b border-border">
                  <th className="pb-2 pr-4 font-medium">Recipient</th>
                  <th className="pb-2 pr-4 font-medium">Type</th>
                  <th className="pb-2 pr-4 font-medium">Status</th>
                  <th className="pb-2 font-medium">Issued</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {recent.map((c) => (
                  <tr key={c.id}>
                    <td className="py-2 pr-4 font-medium">{c.holder_name || '—'}</td>
                    <td className="py-2 pr-4 text-muted-foreground">{c.credential_type || '—'}</td>
                    <td className="py-2 pr-4"><StatusBadge status={c.status} /></td>
                    <td className="py-2 text-muted-foreground">{formatDate(c.issued_at)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Plus, BadgeCheck, ToggleLeft, ToggleRight } from 'lucide-react';
import {
  getCredentialTypes, createCredentialType,
  activateCredentialType, deactivateCredentialType,
} from '../../api/issuer';
import Button from '../../components/common/Button';
import Modal from '../../components/common/Modal';
import Input from '../../components/common/Input';
import Textarea from '../../components/common/Textarea';
import Table from '../../components/common/Table';
import { StatusBadge } from '../../components/common/Badge';
import { formatDate } from '../../utils/formatDate';
import { useForm } from 'react-hook-form';
import toast from 'react-hot-toast';

export default function CredentialTypesPage() {
  const [types, setTypes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const { register, handleSubmit, reset, formState: { errors } } = useForm();

  const load = () => {
    setLoading(true);
    getCredentialTypes()
      .then((r) => setTypes(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const onSubmit = async (data) => {
    setSaving(true);
    try {
      await createCredentialType(data);
      toast.success('Credential type created');
      reset();
      setModal(false);
      load();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to create credential type');
    } finally { setSaving(false); }
  };

  const toggleActive = async (type) => {
    try {
      if (type.is_active) {
        await deactivateCredentialType(type.id);
        toast.success('Credential type deactivated');
      } else {
        await activateCredentialType(type.id);
        toast.success('Credential type activated');
      }
      load();
    } catch {
      toast.error('Failed to update status');
    }
  };

  const columns = [
    { key: 'name', label: 'Name', render: (v, row) => (
      <div>
        <p className="font-medium text-foreground">{v}</p>
        {row.description && <p className="text-xs text-muted-foreground">{row.description}</p>}
      </div>
    )},
    { key: 'category', label: 'Category', render: (v) => v || '—' },
    { key: 'is_active', label: 'Status', render: (v) => <StatusBadge status={v ? 'active' : 'inactive'} /> },
    { key: 'created_at', label: 'Created', render: (v) => formatDate(v) },
    { key: 'actions', label: '', render: (_, row) => (
      <Button
        size="sm"
        variant="ghost"
        onClick={() => toggleActive(row)}
        title={row.is_active ? 'Deactivate' : 'Activate'}
      >
        {row.is_active
          ? <ToggleRight className="h-4 w-4 text-green-500" />
          : <ToggleLeft className="h-4 w-4 text-muted-foreground" />}
      </Button>
    )},
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Credential Types</h1>
          <p className="text-muted-foreground text-sm mt-1">Define the credential types your organization can issue.</p>
        </div>
        <Button onClick={() => setModal(true)}>
          <Plus className="h-4 w-4 mr-2" /> New Type
        </Button>
      </div>

      <Table columns={columns} data={types} loading={loading} emptyMessage="No credential types yet." />

      <Modal isOpen={modal} onClose={() => { setModal(false); reset(); }} title="Create Credential Type">
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <Input
            label="Name"
            {...register('name', { required: 'Name is required' })}
            error={errors.name?.message}
            placeholder="e.g. University Degree"
          />
          <Textarea
            label="Description"
            {...register('description')}
            placeholder="What this credential type represents..."
            rows={3}
          />
          <Input
            label="Category"
            {...register('category')}
            placeholder="e.g. academic, professional"
          />
          <div className="flex gap-3 pt-2">
            <Button type="button" variant="outline" onClick={() => { setModal(false); reset(); }} className="flex-1">
              Cancel
            </Button>
            <Button type="submit" isLoading={saving} className="flex-1">
              Create
            </Button>
          </div>
        </form>
      </Modal>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { Plus, FileText, Eye, ToggleLeft, ToggleRight } from 'lucide-react';
import { getTemplates, activateTemplate, deactivateTemplate } from '../../api/issuer';
import Button from '../../components/common/Button';
import EmptyState from '../../components/common/EmptyState';
import { StatusBadge } from '../../components/common/Badge';
import { formatDate } from '../../utils/formatDate';
import toast from 'react-hot-toast';

export default function TemplatesPage() {
  const [templates, setTemplates] = useState([]);
  const [loading, setLoading] = useState(true);

  const load = () => {
    setLoading(true);
    getTemplates()
      .then((r) => setTemplates(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const toggleActive = async (t) => {
    try {
      if (t.is_active) {
        await deactivateTemplate(t.id);
        toast.success('Template deactivated');
      } else {
        await activateTemplate(t.id);
        toast.success('Template activated');
      }
      load();
    } catch {
      toast.error('Failed to update template status');
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Issuance Templates</h1>
          <p className="text-muted-foreground text-sm mt-1">
            Templates define credential fields, data sources, and visual layout.
          </p>
        </div>
        <Link to="/issuer/templates/new">
          <Button>
            <Plus className="h-4 w-4 mr-2" /> New Template
          </Button>
        </Link>
      </div>

      {loading && (
        <div className="space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="card p-4 animate-pulse">
              <div className="h-4 bg-muted rounded w-1/4 mb-2" />
              <div className="h-3 bg-muted rounded w-1/2" />
            </div>
          ))}
        </div>
      )}

      {!loading && templates.length === 0 && (
        <EmptyState
          icon={FileText}
          title="No templates yet"
          description="Create your first issuance template to define what information goes into credentials."
          action={<Link to="/issuer/templates/new"><Button><Plus className="h-4 w-4 mr-2" />Create Template</Button></Link>}
        />
      )}

      {!loading && templates.length > 0 && (
        <div className="space-y-3">
          {templates.map((t) => (
            <div key={t.id} className="card p-4 flex items-center justify-between">
              <div className="flex items-start gap-3">
                <div className={`p-2 rounded-lg ${t.is_active ? 'bg-blue-50 dark:bg-blue-900/20' : 'bg-muted'}`}>
                  <FileText className={`h-4 w-4 ${t.is_active ? 'text-blue-600' : 'text-muted-foreground'}`} />
                </div>
                <div>
                  <p className="font-medium text-foreground">{t.name}</p>
                  <div className="flex items-center gap-2 mt-0.5">
                    <span className="text-xs text-muted-foreground">v{t.version}</span>
                    {t.credential_type_name && (
                      <span className="text-xs text-muted-foreground">· {t.credential_type_name}</span>
                    )}
                    <span className="text-xs text-muted-foreground">· {(t.fields || []).length} fields</span>
                    <StatusBadge status={t.is_active ? 'active' : 'inactive'} />
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <Link to={`/issuer/templates/${t.id}`}>
                  <Button size="sm" variant="outline">
                    <Eye className="h-3.5 w-3.5 mr-1" /> Edit
                  </Button>
                </Link>
                <Button size="sm" variant="ghost" onClick={() => toggleActive(t)} title={t.is_active ? 'Deactivate' : 'Activate'}>
                  {t.is_active
                    ? <ToggleRight className="h-4 w-4 text-green-500" />
                    : <ToggleLeft className="h-4 w-4 text-muted-foreground" />}
                </Button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useForm, useFieldArray } from 'react-hook-form';
import { Plus, Trash2, ArrowLeft, Eye } from 'lucide-react';
import {
  getTemplate, createTemplate, updateTemplate,
  previewTemplate, getCredentialTypes,
} from '../../api/issuer';
import Input from '../../components/common/Input';
import Textarea from '../../components/common/Textarea';
import Select from '../../components/common/Select';
import Button from '../../components/common/Button';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import toast from 'react-hot-toast';

const FIELD_SOURCES = [
  { value: 'member_api', label: 'From Member API' },
  { value: 'manual', label: 'Manual Entry at Issuance' },
  { value: 'fixed', label: 'Fixed Value' },
];

const FIELD_TYPES = [
  { value: 'text', label: 'Text' },
  { value: 'date', label: 'Date' },
  { value: 'number', label: 'Number' },
  { value: 'boolean', label: 'Yes / No' },
];

export default function TemplateEditorPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isNew = !id || id === 'new';
  const [loading, setLoading] = useState(!isNew);
  const [saving, setSaving] = useState(false);
  const [credentialTypes, setCredentialTypes] = useState([]);
  const [svgPreview, setSvgPreview] = useState('');
  const [previewing, setPreviewing] = useState(false);

  const { register, handleSubmit, control, reset, watch, formState: { errors } } = useForm({
    defaultValues: {
      name: '',
      credential_type_id: '',
      fields: [],
      svg_template: '',
      expiry_days: 365,
    },
  });

  const { fields, append, remove } = useFieldArray({ control, name: 'fields' });

  useEffect(() => {
    getCredentialTypes()
      .then((r) => setCredentialTypes(r.data?.results || r.data || []))
      .catch(() => {});

    if (!isNew) {
      setLoading(true);
      getTemplate(id)
        .then((r) => {
          const t = r.data;
          reset({
            name: t.name,
            credential_type_id: t.credential_type || '',
            fields: t.fields || [],
            svg_template: t.svg_template || '',
            expiry_days: t.issuance_rules?.expiry_days || 365,
          });
        })
        .catch(() => toast.error('Failed to load template'))
        .finally(() => setLoading(false));
    }
  }, [id]);

  const onSubmit = async (data) => {
    setSaving(true);
    const payload = {
      name: data.name,
      credential_type_id: data.credential_type_id || null,
      fields: data.fields,
      svg_template: data.svg_template,
      issuance_rules: { expiry_days: parseInt(data.expiry_days, 10) || 365 },
    };
    try {
      if (isNew) {
        const res = await createTemplate(payload);
        toast.success('Template created successfully');
        navigate(`/issuer/templates/${res.data.id}`);
      } else {
        await updateTemplate(id, payload);
        toast.success('New template version saved');
      }
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to save template');
    } finally { setSaving(false); }
  };

  const handlePreview = async () => {
    if (!id || isNew) {
      // Build a sample from field names
      const fieldList = watch('fields') || [];
      const sampleData = Object.fromEntries(fieldList.map((f) => [f.name, f.label || f.name]));
      const svg = watch('svg_template') || '';
      let rendered = svg;
      for (const [k, v] of Object.entries(sampleData)) {
        rendered = rendered.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'g'), v);
      }
      setSvgPreview(rendered);
      return;
    }
    setPreviewing(true);
    try {
      const fieldList = watch('fields') || [];
      const sampleData = Object.fromEntries(fieldList.map((f) => [f.name, f.label || f.name]));
      const res = await previewTemplate(id, { sample_data: sampleData });
      setSvgPreview(res.data.rendered_svg || '');
    } catch {
      toast.error('Preview failed');
    } finally { setPreviewing(false); }
  };

  if (loading) return <CardSkeleton />;

  return (
    <div className="space-y-6 max-w-3xl">
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate('/issuer/templates')}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div>
          <h1 className="text-2xl font-bold text-foreground">
            {isNew ? 'Create Template' : 'Edit Template'}
          </h1>
          <p className="text-sm text-muted-foreground">
            {isNew ? 'Define fields and layout for this credential.' : 'Saving creates a new version.'}
          </p>
        </div>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
        {/* Basic Info */}
        <div className="card p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">Template Info</h2>
          <Input
            label="Template Name"
            {...register('name', { required: 'Name is required' })}
            error={errors.name?.message}
            placeholder="e.g. University Degree Certificate"
          />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Credential Type" {...register('credential_type_id')}>
              <option value="">— None (auto-create) —</option>
              {credentialTypes.map((ct) => (
                <option key={ct.id} value={ct.id}>{ct.name}</option>
              ))}
            </Select>
            <Input
              label="Validity (days)"
              type="number"
              {...register('expiry_days')}
              placeholder="365"
            />
          </div>
        </div>

        {/* Fields */}
        <div className="card p-6 space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-sm font-semibold text-foreground">Credential Fields</h2>
            <Button
              type="button"
              size="sm"
              variant="outline"
              onClick={() => append({
                name: '', label: '', data_type: 'text',
                source: 'member_api', source_field: '', required: true, default_value: '',
              })}
            >
              <Plus className="h-3.5 w-3.5 mr-1" /> Add Field
            </Button>
          </div>

          {fields.length === 0 && (
            <p className="text-xs text-muted-foreground italic text-center py-4">
              No fields yet. Add fields to define what data this credential contains.
            </p>
          )}

          <div className="space-y-4">
            {fields.map((field, index) => {
              const source = watch(`fields.${index}.source`);
              return (
                <div key={field.id} className="border border-border rounded-lg p-4 space-y-3">
                  <div className="flex items-center justify-between">
                    <span className="text-xs font-medium text-muted-foreground">Field {index + 1}</span>
                    <Button type="button" variant="ghost" size="sm" className="text-red-500"
                      onClick={() => remove(index)}>
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <Input
                      label="Field Key"
                      {...register(`fields.${index}.name`, { required: 'Required' })}
                      placeholder="studentId"
                      hint="Internal key (no spaces)"
                    />
                    <Input
                      label="Display Label"
                      {...register(`fields.${index}.label`)}
                      placeholder="Student ID"
                    />
                  </div>
                  <div className="grid grid-cols-3 gap-3">
                    <Select label="Type" {...register(`fields.${index}.data_type`)}>
                      {FIELD_TYPES.map((t) => <option key={t.value} value={t.value}>{t.label}</option>)}
                    </Select>
                    <Select label="Source" {...register(`fields.${index}.source`)}>
                      {FIELD_SOURCES.map((s) => <option key={s.value} value={s.value}>{s.label}</option>)}
                    </Select>
                    {source === 'member_api' && (
                      <Input
                        label="API Response Field"
                        {...register(`fields.${index}.source_field`)}
                        placeholder="student_id"
                      />
                    )}
                    {source === 'fixed' && (
                      <Input
                        label="Fixed Value"
                        {...register(`fields.${index}.default_value`)}
                        placeholder="Value"
                      />
                    )}
                  </div>
                  <label className="flex items-center gap-2 text-sm cursor-pointer">
                    <input type="checkbox" {...register(`fields.${index}.required`)} className="rounded" />
                    <span className="text-muted-foreground">Required field</span>
                  </label>
                </div>
              );
            })}
          </div>
        </div>

        {/* SVG Template */}
        <div className="card p-6 space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-sm font-semibold text-foreground">Visual Template (SVG)</h2>
            <Button type="button" variant="outline" size="sm" onClick={handlePreview} isLoading={previewing}>
              <Eye className="h-3.5 w-3.5 mr-1" /> Preview
            </Button>
          </div>
          <Textarea
            label="SVG Template"
            {...register('svg_template')}
            placeholder="<svg ...>{{name}}</svg>"
            rows={8}
            hint="Use {{fieldName}} tokens matching your field keys above."
          />
          {svgPreview && (
            <div className="border border-border rounded p-4 bg-white dark:bg-gray-900 overflow-auto max-h-80">
              <div dangerouslySetInnerHTML={{ __html: svgPreview }} />
            </div>
          )}
        </div>

        <div className="flex gap-3">
          <Button type="button" variant="outline" onClick={() => navigate('/issuer/templates')} className="flex-1">
            Cancel
          </Button>
          <Button type="submit" isLoading={saving} className="flex-1">
            {isNew ? 'Create Template' : 'Save New Version'}
          </Button>
        </div>
      </form>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { getIssuedCredentials, revokeCredential, suspendCredential, reinstateCredential } from '../../api/issuer';
import Table from '../../components/common/Table';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import Select from '../../components/common/Select';
import Modal from '../../components/common/Modal';
import { formatDate } from '../../utils/formatDate';
import toast from 'react-hot-toast';
import { BadgeCheck, Search, AlertTriangle } from 'lucide-react';

export default function IssuedCredentialsPage() {
  const [searchParams] = useSearchParams();
  const [credentials, setCredentials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState(searchParams.get('status') || '');
  const [actionModal, setActionModal] = useState(null); // {type: 'revoke'|'suspend', id}
  const [reason, setReason] = useState('');
  const [actioning, setActioning] = useState(false);

  const load = () => {
    setLoading(true);
    const params = { page, page_size: 20 };
    if (statusFilter) params.status = statusFilter;
    if (search) params.search = search;
    getIssuedCredentials(params)
      .then((r) => {
        setCredentials(r.data?.results || r.data || []);
        setTotal(r.data?.count || 0);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [page, statusFilter, search]);

  const handleAction = async () => {
    if (!reason.trim()) { toast.error('Reason is required'); return; }
    setActioning(true);
    try {
      if (actionModal.type === 'revoke') {
        await revokeCredential(actionModal.id, { reason });
        toast.success('Credential revoked');
      } else if (actionModal.type === 'suspend') {
        await suspendCredential(actionModal.id, { reason });
        toast.success('Credential suspended');
      }
      setActionModal(null);
      setReason('');
      load();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Action failed');
    } finally { setActioning(false); }
  };

  const handleReinstate = async (id) => {
    try {
      await reinstateCredential(id);
      toast.success('Credential reinstated');
      load();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Reinstate failed');
    }
  };

  const columns = [
    { key: 'holder_name', label: 'Recipient', render: (v, row) => (
      <div>
        <p className="font-medium text-foreground">{v || '—'}</p>
        {row.pending_holder_registration && (
          <span className="text-xs text-orange-500">Awaiting wallet</span>
        )}
      </div>
    )},
    { key: 'credential_type', label: 'Type', render: (v) => v || '—' },
    { key: 'status', label: 'Status', render: (v, row) => (
      <div className="flex flex-col gap-0.5">
        <StatusBadge status={v} />
        {row.render_metadata?.suspended && (
          <span className="text-xs text-yellow-500">Suspended</span>
        )}
      </div>
    )},
    { key: 'issued_at', label: 'Issued', render: (v) => formatDate(v) },
    { key: 'expires_at', label: 'Expires', render: (v) => v ? formatDate(v) : '—' },
    { key: 'actions', label: '', render: (_, row) => (
      <div className="flex gap-1">
        {row.status === 'active' && !row.render_metadata?.suspended && (
          <>
            <Button size="sm" variant="outline" className="text-yellow-600 border-yellow-200"
              onClick={() => setActionModal({ type: 'suspend', id: row.id })}>
              Suspend
            </Button>
            <Button size="sm" variant="outline" className="text-red-500 border-red-200"
              onClick={() => setActionModal({ type: 'revoke', id: row.id })}>
              Revoke
            </Button>
          </>
        )}
        {row.render_metadata?.suspended && (
          <Button size="sm" variant="outline" className="text-green-600"
            onClick={() => handleReinstate(row.id)}>
            Reinstate
          </Button>
        )}
        {row.status === 'revoked' && (
          <Button size="sm" variant="outline" className="text-green-600"
            onClick={() => handleReinstate(row.id)}>
            Reinstate
          </Button>
        )}
      </div>
    )},
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Issued Credentials</h1>
          <p className="text-muted-foreground text-sm mt-1">{total} credential{total !== 1 ? 's' : ''} total</p>
        </div>
        <Link to="/issuer/issue">
          <Button><BadgeCheck className="h-4 w-4 mr-2" /> Issue New</Button>
        </Link>
      </div>

      {/* Filters */}
      <div className="flex gap-3">
        <div className="flex-1 relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <input
            className="input pl-9 w-full"
            placeholder="Search by name or identifier..."
            value={search}
            onChange={(e) => { setSearch(e.target.value); setPage(1); }}
          />
        </div>
        <Select value={statusFilter} onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}>
          <option value="">All statuses</option>
          <option value="active">Active</option>
          <option value="revoked">Revoked</option>
          <option value="expired">Expired</option>
        </Select>
      </div>

      <Table columns={columns} data={credentials} loading={loading} emptyMessage="No credentials found." />

      {/* Pagination */}
      {total > 20 && (
        <div className="flex items-center justify-center gap-2 text-sm">
          <Button variant="outline" size="sm" disabled={page === 1} onClick={() => setPage(p => p - 1)}>
            Previous
          </Button>
          <span className="text-muted-foreground">Page {page} of {Math.ceil(total / 20)}</span>
          <Button variant="outline" size="sm" disabled={page >= Math.ceil(total / 20)} onClick={() => setPage(p => p + 1)}>
            Next
          </Button>
        </div>
      )}

      {/* Action Modal */}
      <Modal
        isOpen={!!actionModal}
        onClose={() => { setActionModal(null); setReason(''); }}
        title={actionModal?.type === 'revoke' ? 'Revoke Credential' : 'Suspend Credential'}
      >
        <div className="space-y-4">
          <div className="flex items-start gap-2 p-3 rounded bg-red-50 dark:bg-red-900/20 text-sm text-red-700 dark:text-red-300">
            <AlertTriangle className="h-4 w-4 mt-0.5 flex-shrink-0" />
            <p>
              {actionModal?.type === 'revoke'
                ? 'Revoking is permanent and will invalidate this credential for verification.'
                : 'Suspending temporarily disables this credential. You can reinstate it later.'}
            </p>
          </div>
          <Input
            label="Reason"
            value={reason}
            onChange={(e) => setReason(e.target.value)}
            placeholder="Explain why..."
          />
          <div className="flex gap-3">
            <Button variant="outline" className="flex-1" onClick={() => { setActionModal(null); setReason(''); }}>
              Cancel
            </Button>
            <Button
              className={`flex-1 ${actionModal?.type === 'revoke' ? 'bg-red-500 hover:bg-red-600 text-white' : 'bg-yellow-500 hover:bg-yellow-600 text-white'}`}
              isLoading={actioning}
              onClick={handleAction}
            >
              {actionModal?.type === 'revoke' ? 'Revoke' : 'Suspend'}
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import {
  getIssuerRequests, approveRequest, rejectRequest,
  bulkApproveRequests, bulkRejectRequests,
} from '../../api/issuer';
import Table from '../../components/common/Table';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Select from '../../components/common/Select';
import Modal from '../../components/common/Modal';
import Input from '../../components/common/Input';
import { formatDate } from '../../utils/formatDate';
import toast from 'react-hot-toast';
import { CheckCircle2, XCircle, Loader2 } from 'lucide-react';

export default function RequestsPage() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('');
  const [selected, setSelected] = useState([]);
  const [rejectModal, setRejectModal] = useState(null);
  const [rejectReason, setRejectReason] = useState('');
  const [actioning, setActioning] = useState(false);

  const load = () => {
    setLoading(true);
    const params = {};
    if (statusFilter) params.status = statusFilter;
    getIssuerRequests(params)
      .then((r) => setRequests(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); setSelected([]); }, [statusFilter]);

  const approve = async (id) => {
    try {
      await approveRequest(id);
      toast.success('Request approved and credential issued');
      load();
    } catch (err) {
      toast.error(err.response?.data?.error || err.response?.data?.detail || 'Approval failed');
    }
  };

  const reject = async () => {
    if (!rejectReason.trim()) { toast.error('Reason is required'); return; }
    setActioning(true);
    try {
      await rejectRequest(rejectModal, { reason: rejectReason });
      toast.success('Request rejected');
      setRejectModal(null);
      setRejectReason('');
      load();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Rejection failed');
    } finally { setActioning(false); }
  };

  const bulkApprove = async () => {
    if (!selected.length) return;
    try {
      const res = await bulkApproveRequests({ request_ids: selected });
      toast.success(`${res.data.approved?.length || 0} approved`);
      if (res.data.failed?.length) toast.error(`${res.data.failed.length} failed`);
      setSelected([]);
      load();
    } catch {
      toast.error('Bulk approve failed');
    }
  };

  const bulkReject = async () => {
    if (!selected.length) return;
    try {
      await bulkRejectRequests({ request_ids: selected, reason: 'Bulk rejected' });
      toast.success(`${selected.length} rejected`);
      setSelected([]);
      load();
    } catch {
      toast.error('Bulk reject failed');
    }
  };

  const toggleSelect = (id) => {
    setSelected((prev) => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const columns = [
    { key: 'select', label: '', render: (_, row) => row.status === 'pending' ? (
      <input type="checkbox" checked={selected.includes(row.id)}
        onChange={() => toggleSelect(row.id)} className="rounded" />
    ) : null },
    { key: 'holder_name', label: 'Holder', render: (v, row) => (
      <div>
        <p className="font-medium">{v || row.holder_email || '—'}</p>
        {row.holder_national_id && <p className="text-xs text-muted-foreground">{row.holder_national_id}</p>}
      </div>
    )},
    { key: 'credential_type', label: 'Credential Type' },
    { key: 'status', label: 'Status', render: (v) => <StatusBadge status={v} /> },
    { key: 'created_at', label: 'Requested', render: (v) => formatDate(v) },
    { key: 'actions', label: '', render: (_, row) => row.status === 'pending' ? (
      <div className="flex gap-1">
        <Button size="sm" variant="outline" className="text-green-600 border-green-200"
          onClick={() => approve(row.id)}>
          <CheckCircle2 className="h-3.5 w-3.5 mr-1" /> Approve
        </Button>
        <Button size="sm" variant="outline" className="text-red-500 border-red-200"
          onClick={() => { setRejectModal(row.id); setRejectReason(''); }}>
          <XCircle className="h-3.5 w-3.5 mr-1" /> Reject
        </Button>
      </div>
    ) : null },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Credential Requests</h1>
          <p className="text-muted-foreground text-sm mt-1">Review and respond to holder requests.</p>
        </div>
        {selected.length > 0 && (
          <div className="flex gap-2">
            <Button size="sm" variant="outline" className="text-green-600" onClick={bulkApprove}>
              Approve {selected.length}
            </Button>
            <Button size="sm" variant="outline" className="text-red-500" onClick={bulkReject}>
              Reject {selected.length}
            </Button>
          </div>
        )}
      </div>

      <div className="flex gap-3">
        <Select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="">All statuses</option>
          <option value="pending">Pending</option>
          <option value="issued">Issued</option>
          <option value="rejected">Rejected</option>
        </Select>
      </div>

      <Table columns={columns} data={requests} loading={loading} emptyMessage="No requests found." />

      <Modal isOpen={!!rejectModal} onClose={() => { setRejectModal(null); setRejectReason(''); }} title="Reject Request">
        <div className="space-y-4">
          <Input
            label="Reason for rejection"
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            placeholder="Explain why..."
          />
          <div className="flex gap-3">
            <Button variant="outline" className="flex-1" onClick={() => setRejectModal(null)}>Cancel</Button>
            <Button className="flex-1 bg-red-500 hover:bg-red-600 text-white" isLoading={actioning} onClick={reject}>
              Reject
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import { useEffect, useState } from 'react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, LineChart, Line, PieChart, Pie, Cell, Legend,
} from 'recharts';
import {
  getIssuerAnalyticsStats, getIssuerAnalyticsTrends,
  getIssuerAnalyticsByType, getIssuerAnalyticsFailures,
} from '../../api/issuer';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

export default function AnalyticsPage() {
  const [stats, setStats] = useState(null);
  const [trends, setTrends] = useState([]);
  const [byType, setByType] = useState([]);
  const [failures, setFailures] = useState([]);
  const [loading, setLoading] = useState(true);
  const [range, setRange] = useState(30);

  const load = () => {
    setLoading(true);
    const endDate = new Date().toISOString().split('T')[0];
    const startDate = new Date(Date.now() - range * 86400000).toISOString().split('T')[0];
    Promise.all([
      getIssuerAnalyticsStats(),
      getIssuerAnalyticsTrends({ start_date: startDate, end_date: endDate }),
      getIssuerAnalyticsByType(),
      getIssuerAnalyticsFailures(),
    ]).then(([s, t, bt, f]) => {
      setStats(s.data);
      setTrends(t.data || []);
      setByType(bt.data || []);
      setFailures(f.data || []);
    }).catch(() => {}).finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [range]);

  if (loading) return <div className="space-y-4"><CardSkeleton /><CardSkeleton /><CardSkeleton /></div>;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Analytics</h1>
          <p className="text-muted-foreground text-sm mt-1">Credential issuance statistics and trends.</p>
        </div>
        <div className="flex gap-2">
          {[7, 30, 90].map((d) => (
            <button
              key={d}
              onClick={() => setRange(d)}
              className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${range === d ? 'bg-primary text-primary-foreground border-primary' : 'border-border text-muted-foreground hover:bg-muted'}`}
            >
              {d}d
            </button>
          ))}
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {[
          { label: 'Total Issued', value: stats?.total_issued ?? 0 },
          { label: 'Active', value: stats?.active_count ?? 0 },
          { label: 'Revoked', value: stats?.revoked_count ?? 0 },
          { label: 'Month-over-Month', value: `${stats?.month_over_month_change ?? 0}%`, positive: (stats?.month_over_month_change ?? 0) >= 0 },
        ].map((s) => (
          <div key={s.label} className="card p-4 text-center">
            <p className={`text-2xl font-bold ${s.positive !== undefined ? (s.positive ? 'text-green-600' : 'text-red-500') : 'text-foreground'}`}>
              {s.value}
            </p>
            <p className="text-xs text-muted-foreground mt-1">{s.label}</p>
          </div>
        ))}
      </div>

      {/* Issuance Trend */}
      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground">Issuance Trend</h2>
        {trends.length === 0 ? (
          <p className="text-center text-muted-foreground text-sm py-8">No data for this period.</p>
        ) : (
          <ResponsiveContainer width="100%" height={200}>
            <LineChart data={trends}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(0,0,0,0.05)" />
              <XAxis dataKey="date" tick={{ fontSize: 10 }} tickFormatter={(d) => d.slice(5)} />
              <YAxis tick={{ fontSize: 10 }} />
              <Tooltip labelFormatter={(d) => formatDate(d)} />
              <Line type="monotone" dataKey="count" stroke="#6366f1" strokeWidth={2} dot={false} name="Issued" />
            </LineChart>
          </ResponsiveContainer>
        )}
      </div>

      <div className="grid sm:grid-cols-2 gap-6">
        {/* By Type */}
        <div className="card p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">By Credential Type</h2>
          {byType.length === 0 ? (
            <p className="text-center text-muted-foreground text-sm py-8">No data yet.</p>
          ) : (
            <ResponsiveContainer width="100%" height={200}>
              <PieChart>
                <Pie data={byType} dataKey="count" nameKey="type" cx="50%" cy="50%" outerRadius={80} label>
                  {byType.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          )}
        </div>

        {/* Failure Analysis */}
        <div className="card p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">Failure Analysis (Last 30 days)</h2>
          {failures.length === 0 ? (
            <p className="text-center text-muted-foreground text-sm py-8">No failures recorded.</p>
          ) : (
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={failures} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(0,0,0,0.05)" />
                <XAxis type="number" tick={{ fontSize: 10 }} />
                <YAxis dataKey="reason" type="category" tick={{ fontSize: 10 }} width={120} />
                <Tooltip />
                <Bar dataKey="count" fill="#ef4444" name="Failures" />
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useForm } from 'react-hook-form';
import { getIssuerProfile, updateIssuerProfile, getIssuerAuditLog } from '../../api/issuer';
import { changePassword } from '../../api/auth';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';
import toast from 'react-hot-toast';
import { Settings, Lock, FileText } from 'lucide-react';

export default function SettingsPage() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [changingPwd, setChangingPwd] = useState(false);
  const [auditLogs, setAuditLogs] = useState([]);
  const [logsLoading, setLogsLoading] = useState(true);

  const profileForm = useForm({ defaultValues: { contact_person_name: '', contact_person_email: '', phone: '' } });
  const pwdForm = useForm({ defaultValues: { current_password: '', new_password: '', confirm_password: '' } });

  useEffect(() => {
    getIssuerProfile()
      .then((r) => {
        profileForm.reset({
          contact_person_name: r.data?.contact_person_name || '',
          contact_person_email: r.data?.contact_person_email || r.data?.email || '',
          phone: r.data?.phone || '',
        });
      })
      .catch(() => {})
      .finally(() => setLoading(false));

    getIssuerAuditLog({ page_size: 20 })
      .then((r) => setAuditLogs(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLogsLoading(false));
  }, []);

  const saveProfile = async (data) => {
    setSaving(true);
    try {
      await updateIssuerProfile(data);
      toast.success('Profile updated');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to update profile');
    } finally { setSaving(false); }
  };

  const savePassword = async (data) => {
    if (data.new_password !== data.confirm_password) {
      toast.error('New passwords do not match');
      return;
    }
    setChangingPwd(true);
    try {
      await changePassword({ current_password: data.current_password, new_password: data.new_password });
      toast.success('Password changed successfully');
      pwdForm.reset();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to change password');
    } finally { setChangingPwd(false); }
  };

  if (loading) return <CardSkeleton />;

  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
          <Settings className="h-6 w-6" /> Settings
        </h1>
        <p className="text-muted-foreground text-sm mt-1">Manage your account and organization settings.</p>
      </div>

      {/* Profile */}
      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground">Contact Information</h2>
        <form onSubmit={profileForm.handleSubmit(saveProfile)} className="space-y-4">
          <Input label="Contact Person Name" {...profileForm.register('contact_person_name')} />
          <Input label="Contact Email" type="email" {...profileForm.register('contact_person_email')} />
          <Input label="Phone" {...profileForm.register('phone')} />
          <Button type="submit" isLoading={saving}>Save Changes</Button>
        </form>
      </div>

      {/* Password */}
      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground flex items-center gap-2">
          <Lock className="h-4 w-4" /> Change Password
        </h2>
        <form onSubmit={pwdForm.handleSubmit(savePassword)} className="space-y-4">
          <Input label="Current Password" type="password" {...pwdForm.register('current_password', { required: true })} />
          <Input label="New Password" type="password" {...pwdForm.register('new_password', { required: true, minLength: 8 })} />
          <Input label="Confirm New Password" type="password" {...pwdForm.register('confirm_password', { required: true })} />
          <Button type="submit" isLoading={changingPwd}>Change Password</Button>
        </form>
      </div>

      {/* Audit Log */}
      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground flex items-center gap-2">
          <FileText className="h-4 w-4" /> Recent Activity Log
        </h2>
        {logsLoading ? (
          <CardSkeleton />
        ) : auditLogs.length === 0 ? (
          <p className="text-sm text-muted-foreground italic">No audit log entries yet.</p>
        ) : (
          <div className="space-y-2 max-h-64 overflow-y-auto">
            {auditLogs.map((log, i) => (
              <div key={i} className="flex items-start gap-3 text-xs py-2 border-b border-border last:border-0">
                <span className="text-muted-foreground whitespace-nowrap">
                  {formatDate(log.timestamp || log.created_at)}
                </span>
                <span className="font-medium text-foreground">{log.action_type || log.action || '—'}</span>
                <span className="text-muted-foreground">{log.entity_type || ''}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import Input from '../../components/common/Input';
import Textarea from '../../components/common/Textarea';
import Select from '../../components/common/Select';
import Button from '../../components/common/Button';
import FileUpload from '../../components/common/FileUpload';
import {
  registrationStep1, registrationVerifyOTP,
  registrationStep2, registrationStep3,
  registrationStep4, registrationStep5,
} from '../../api/issuer';
import toast from 'react-hot-toast';
import { CheckCircle2, ArrowLeft, Building2, FileText, Users, Send } from 'lucide-react';

const STEPS = [
  { label: 'Account', icon: Users },
  { label: 'Verify Email', icon: CheckCircle2 },
  { label: 'Organization', icon: Building2 },
  { label: 'Documents', icon: FileText },
  { label: 'Use Case', icon: Building2 },
  { label: 'Submit', icon: Send },
];

export default function OrgRegisterPage() {
  const navigate = useNavigate();
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [registrationId, setRegistrationId] = useState(null);
  const [otp, setOtp] = useState('');
  const [email, setEmail] = useState('');
  const [docs, setDocs] = useState([]);
  const [docTypes, setDocTypes] = useState([]);
  const [submitted, setSubmitted] = useState(false);

  const { register, handleSubmit, formState: { errors }, getValues } = useForm();

  const next = () => setStep((s) => s + 1);

  // Step 0: Account + request email OTP
  const handleStep0 = async (data) => {
    setLoading(true);
    try {
      const res = await registrationStep1({ email: data.email, password: data.password });
      setRegistrationId(res.data.registration_id);
      setEmail(data.email);
      toast.success('Verification code sent to your email');
      next();
    } catch (err) {
      toast.error(err.response?.data?.error || err.response?.data?.detail || 'Failed to start registration');
    } finally { setLoading(false); }
  };

  // Step 1: Verify OTP
  const handleOtpVerify = async (e) => {
    e.preventDefault();
    if (!otp || otp.length < 6) { toast.error('Please enter the 6-digit code'); return; }
    setLoading(true);
    try {
      await registrationVerifyOTP({ registration_id: registrationId, otp });
      toast.success('Email verified successfully');
      next();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Invalid or expired verification code');
    } finally { setLoading(false); }
  };

  // Step 2: Organization details
  const handleStep2 = async (data) => {
    setLoading(true);
    try {
      await registrationStep2({
        registration_id: registrationId,
        organization_name: data.organization_name,
        address: data.address,
        phone: data.phone,
        website: data.website,
        contact_person_name: data.contact_person_name,
        contact_person_email: data.contact_person_email,
      });
      toast.success('Organization details saved');
      next();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to save organization details');
    } finally { setLoading(false); }
  };

  // Step 3: Documents
  const handleStep3 = async () => {
    if (!docs.length) { toast.error('Please upload at least one document'); return; }
    setLoading(true);
    const fd = new FormData();
    fd.append('registration_id', registrationId);
    docs.forEach((f, i) => {
      fd.append('files', f);
      fd.append('document_types', docTypes[i] || 'other');
    });
    try {
      await registrationStep3(fd, { headers: { 'Content-Type': 'multipart/form-data' } });
      toast.success('Documents uploaded');
      next();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to upload documents');
    } finally { setLoading(false); }
  };

  // Step 4: Use case
  const handleStep4 = async (data) => {
    setLoading(true);
    try {
      await registrationStep4({
        registration_id: registrationId,
        use_case_description: data.use_case_description,
        intended_credential_types: data.intended_credential_types
          ? data.intended_credential_types.split(',').map(s => s.trim()).filter(Boolean)
          : [],
      });
      toast.success('Use case saved');
      next();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to save use case');
    } finally { setLoading(false); }
  };

  // Step 5: Submit
  const handleStep5 = async (data) => {
    if (!data.consent) { toast.error('Please agree to the terms and conditions'); return; }
    setLoading(true);
    try {
      await registrationStep5({ registration_id: registrationId, consent: true });
      setSubmitted(true);
      toast.success('Application submitted successfully!');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Submission failed');
    } finally { setLoading(false); }
  };

  if (submitted) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background p-4">
        <div className="card p-8 max-w-md text-center space-y-4">
          <CheckCircle2 className="h-16 w-16 text-green-500 mx-auto" />
          <h1 className="text-2xl font-bold text-foreground">Application Submitted!</h1>
          <p className="text-muted-foreground">
            Your issuer registration has been submitted successfully. Our team will review your
            application within 3-5 business days. You'll receive an email notification once approved.
          </p>
          <p className="text-xs text-muted-foreground">Registration ID: <span className="font-mono">{registrationId}</span></p>
          <Link to="/auth/login">
            <Button className="w-full mt-2">Go to Login</Button>
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Header */}
      <div className="border-b border-border p-4 flex items-center gap-4">
        <Link to="/auth/login" className="text-muted-foreground hover:text-foreground">
          <ArrowLeft className="h-5 w-5" />
        </Link>
        <div>
          <h1 className="font-bold text-foreground">Issuer Registration</h1>
          <p className="text-xs text-muted-foreground">Step {step + 1} of {STEPS.length}</p>
        </div>
      </div>

      {/* Step Indicator */}
      <div className="border-b border-border overflow-x-auto">
        <div className="flex min-w-max px-4 py-3 gap-0">
          {STEPS.map((s, i) => (
            <div key={i} className="flex items-center">
              <div className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium transition-colors ${
                i === step ? 'bg-primary text-primary-foreground' :
                i < step ? 'bg-green-100 dark:bg-green-900/20 text-green-700 dark:text-green-300' :
                'text-muted-foreground'
              }`}>
                {i < step ? <CheckCircle2 className="h-3 w-3" /> : <s.icon className="h-3 w-3" />}
                {s.label}
              </div>
              {i < STEPS.length - 1 && <div className="w-4 h-px bg-border mx-1" />}
            </div>
          ))}
        </div>
      </div>

      {/* Form Area */}
      <div className="flex-1 flex items-start justify-center p-6">
        <div className="w-full max-w-lg space-y-6">
          {/* Step 0: Account */}
          {step === 0 && (
            <form onSubmit={handleSubmit(handleStep0)} className="card p-6 space-y-4">
              <div>
                <h2 className="text-lg font-semibold">Create Your Account</h2>
                <p className="text-sm text-muted-foreground">Start your issuer registration journey.</p>
              </div>
              <Input
                label="Email Address"
                type="email"
                {...register('email', { required: 'Email is required' })}
                error={errors.email?.message}
                placeholder="you@organization.edu"
              />
              <Input
                label="Password"
                type="password"
                {...register('password', { required: 'Password is required', minLength: { value: 8, message: 'At least 8 characters' } })}
                error={errors.password?.message}
                placeholder="Create a strong password"
              />
              <Button type="submit" isLoading={loading} className="w-full">
                Continue
              </Button>
              <p className="text-center text-xs text-muted-foreground">
                Already have an account?{' '}
                <Link to="/auth/login" className="text-primary hover:underline">Login</Link>
              </p>
            </form>
          )}

          {/* Step 1: OTP Verification */}
          {step === 1 && (
            <form onSubmit={handleOtpVerify} className="card p-6 space-y-4">
              <div>
                <h2 className="text-lg font-semibold">Verify Your Email</h2>
                <p className="text-sm text-muted-foreground">
                  We sent a 6-digit code to <strong>{email}</strong>
                </p>
              </div>
              <Input
                label="Verification Code"
                value={otp}
                onChange={(e) => setOtp(e.target.value.replace(/\D/g, '').slice(0, 6))}
                maxLength={6}
                placeholder="000000"
                className="text-center text-2xl tracking-widest"
              />
              <Button type="submit" isLoading={loading} className="w-full" disabled={otp.length < 6}>
                Verify Email
              </Button>
              <button
                type="button"
                className="w-full text-sm text-muted-foreground hover:text-foreground"
                onClick={() => { setStep(0); setOtp(''); }}
              >
                ← Back to change email
              </button>
            </form>
          )}

          {/* Step 2: Organization Details */}
          {step === 2 && (
            <form onSubmit={handleSubmit(handleStep2)} className="card p-6 space-y-4">
              <div>
                <h2 className="text-lg font-semibold">Organization Details</h2>
                <p className="text-sm text-muted-foreground">Tell us about your organization.</p>
              </div>
              <Input
                label="Organization Name"
                {...register('organization_name', { required: 'Organization name is required' })}
                error={errors.organization_name?.message}
                placeholder="e.g. University of Technology"
              />
              <Textarea
                label="Address"
                {...register('address', { required: 'Address is required' })}
                error={errors.address?.message}
                placeholder="Full mailing address"
                rows={2}
              />
              <div className="grid grid-cols-2 gap-4">
                <Input label="Phone" {...register('phone')} placeholder="+1-xxx-xxx-xxxx" />
                <Input label="Website" type="url" {...register('website')} placeholder="https://..." />
              </div>
              <Input
                label="Contact Person Name"
                {...register('contact_person_name', { required: 'Contact person name is required' })}
                error={errors.contact_person_name?.message}
                placeholder="Full name"
              />
              <Input
                label="Contact Person Email"
                type="email"
                {...register('contact_person_email')}
                placeholder="Contact email"
              />
              <Button type="submit" isLoading={loading} className="w-full">Continue</Button>
            </form>
          )}

          {/* Step 3: Documents */}
          {step === 3 && (
            <div className="card p-6 space-y-4">
              <div>
                <h2 className="text-lg font-semibold">Upload Documents</h2>
                <p className="text-sm text-muted-foreground">
                  Upload supporting documents to verify your organization (e.g., business license, accreditation certificate).
                </p>
              </div>
              <FileUpload
                accept=".pdf,.jpg,.jpeg,.png"
                maxFiles={5}
                onFilesChange={(files) => {
                  setDocs(files);
                  setDocTypes(files.map(() => 'business_license'));
                }}
              />
              {docs.length > 0 && (
                <div className="space-y-2">
                  {docs.map((f, i) => (
                    <div key={i} className="flex items-center gap-3">
                      <span className="text-xs text-foreground flex-1">{f.name}</span>
                      <select
                        className="input text-xs py-1"
                        value={docTypes[i] || 'other'}
                        onChange={(e) => {
                          const updated = [...docTypes];
                          updated[i] = e.target.value;
                          setDocTypes(updated);
                        }}
                      >
                        <option value="business_license">Business License</option>
                        <option value="tax_clearance">Tax Clearance</option>
                        <option value="accreditation_certificate">Accreditation Certificate</option>
                        <option value="authorization_letter">Authorization Letter</option>
                        <option value="other">Other</option>
                      </select>
                    </div>
                  ))}
                </div>
              )}
              <Button onClick={handleStep3} isLoading={loading} className="w-full" disabled={!docs.length}>
                Upload & Continue
              </Button>
            </div>
          )}

          {/* Step 4: Use Case */}
          {step === 4 && (
            <form onSubmit={handleSubmit(handleStep4)} className="card p-6 space-y-4">
              <div>
                <h2 className="text-lg font-semibold">Use Case Description</h2>
                <p className="text-sm text-muted-foreground">Explain how you plan to use the credential issuance system.</p>
              </div>
              <Textarea
                label="How will you use this platform?"
                {...register('use_case_description', { required: 'Please describe your use case' })}
                error={errors.use_case_description?.message}
                placeholder="e.g. We will issue digital academic certificates to graduating students..."
                rows={4}
              />
              <Input
                label="Intended Credential Types (comma-separated)"
                {...register('intended_credential_types')}
                placeholder="e.g. Academic Degree, Professional Certificate, Transcript"
              />
              <Button type="submit" isLoading={loading} className="w-full">Continue</Button>
            </form>
          )}

          {/* Step 5: Submit */}
          {step === 5 && (
            <form onSubmit={handleSubmit(handleStep5)} className="card p-6 space-y-4">
              <div>
                <h2 className="text-lg font-semibold">Review & Submit</h2>
                <p className="text-sm text-muted-foreground">
                  Review your application before submission.
                </p>
              </div>
              <div className="bg-muted/40 rounded p-4 space-y-2 text-sm">
                <p><span className="text-muted-foreground">Email:</span> {email}</p>
                <p><span className="text-muted-foreground">Org:</span> {getValues('organization_name')}</p>
                <p><span className="text-muted-foreground">Contact:</span> {getValues('contact_person_name')}</p>
              </div>
              <div className="border border-border rounded p-4 bg-muted/20 text-xs text-muted-foreground space-y-2">
                <p className="font-medium text-foreground text-sm">Terms & Conditions</p>
                <p>By submitting this application, you confirm that all information provided is accurate and
                  your organization is authorized to issue digital credentials through this platform.
                  Misuse or fraudulent information will result in application rejection and possible suspension.</p>
              </div>
              <label className="flex items-start gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  {...register('consent', { required: true })}
                  className="mt-0.5 rounded"
                />
                <span className="text-sm text-foreground">
                  I agree to the platform terms and conditions and confirm all information is accurate.
                </span>
              </label>
              {errors.consent && <p className="text-xs text-red-500">You must agree to proceed</p>}
              <Button type="submit" isLoading={loading} className="w-full">
                <Send className="h-4 w-4 mr-2" /> Submit Application
              </Button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

